/* selectStockListForShipPlan */ SELECT
CONCAT(WS.STOCKKY) AS ROWKEY,
WS.STOCKKY,
WS.WAREKEY, WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER, WS.SAVEPNT, WS.LOTNMKY, WS.OWNERKY, WS.OWNRNAM, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY, WS.FCNAMLC, WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC, WS.STLOTNB, WS.GROSSWG, WS.GROSSLN, WS.GROSSWD, WS.GROSSTH, WS.BTRCATE, WS.BTRFSTC, WS.PURCNUM, WS.ORDERLN, WS.REGIKEY, WS.DESTKEY, WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DEORGNM, WS.DESTMOD, WS.ITEMCOD, WS.DEMODNM, WS.DEMODYN, WS.DEMDMAN, WS.DEMPOCD, WS.DEMDADR, WS.DEMDTLN, WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY, WS.SUOMKEY, WS.ADDCOKY, WS.POSHPDT, WS.POSHPTM, WS.POSHPDY, WS.SHPLIMT, WS.DELVDSR, WS.STKMEMO, WS.EMSKUYN, WS.RCVDCDT, WS.LOTAT01, WS.LOTAT02, WS.LOTAT03, WS.STKSTAT, WS.BLOCKID, WS.RCVDCKY, WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY, WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY, WS.TASKOIT,
MR1.RENAMLC AS REORGNM, MR2.RENAMLC AS REMODNM, MW.WHNAMLC AS WHNAMLC, MA.AREANAM AS AREANAM, ML.LOCANAM AS LOCANAM, MCO1.COMCDTX AS STKSTNM, WR.RCVDCDT, WR.RCVDCTM, MC02.COMCDTX AS ADDCONM, (SELECT M.GRPKYNM FROM ${userData.schema}.MGRPMA M WHERE M.SKUGRKY = WS.SKUGRKY) AS GRPKYNM, BTC.BTRCNAM,
DATE_FORMAT(WS.CREDATE, '%Y-%m-%d') AS CREDATE, DATE_FORMAT(STR_TO_DATE(WS.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WS.CREUSER) AS CREUSER, DATE_FORMAT(WS.LMODATE, '%Y-%m-%d') AS LMODATE, DATE_FORMAT(STR_TO_DATE(WS.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER, WS.UPDTCHK FROM ${userData.schema}.WSTKKY WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.AREAKEY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WS.WAREKEY AND ML.AREAKEY = WS.AREAKEY AND ML.LOCAKEY = WS.LOCAKEY AND ML.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MCO1 ON MCO1.COMCDVL = WS.STKSTAT AND MCO1.COMCDKY = 'STKSTAT' AND MCO1.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = WS.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC02 ON BA.ADDSIKY = MC02.COMCDVL AND MC02.COMCDKY = 'ADDSIKY' AND MC02.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.WRCVIT WR ON WR.RCVDCKY = WS.RCVDCKY AND WR.RCVDCIT = WS.RCVDCIT AND WR.SKUMKEY = WS.SKUMKEY INNER JOIN ${userData.schema}.BTRCAT BTC ON BTC.BTRCATE = WS.BTRCATE WHERE WS.WAREKEY = #{param.warekey} AND WS.STOTQTY > 0 AND WS.SALLQTY = 0 AND WS.SBLOQTY = 0 AND WS.PLANQTY = 0 AND WS.PLCMQTY = 0 AND WS.TASKQTY = 0 AND WS.STKSTAT = '00' AND ML.LOCTYPE = 'BED'
AND UPPER(TRIM(WS.CUSTNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.custnam})), '%')
AND UPPER(TRIM(WS.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND UPPER(TRIM(WS.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND UPPER(TRIM(WS.LOCAKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.locakey})), '%')
AND UPPER(TRIM(WS.LOCAKEY)) IN
UPPER(TRIM(#{locakey}))
AND UPPER(TRIM(WS.ITEMCOD)) LIKE CONCAT('%',UPPER(TRIM(#{param.itemcod})), '%')
AND UPPER(TRIM(WS.ITEMCOD)) IN
UPPER(TRIM(#{itemcod}))
AND UPPER(TRIM(WS.PURCNUM)) LIKE CONCAT('%', UPPER(TRIM(#{param.purcnum})), '%')
AND UPPER(TRIM(WS.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND UPPER(TRIM(WS.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WS.REGIMOD = #{param.regikey}
AND WS.DESTMOD = #{param.destkey}
AND WS.SKUGRKY IN ( SELECT SKUGRKY FROM ${userData.schema}.MGRPMA WHERE SZGUBUN >= (SELECT SZGUBUN FROM ${userData.schema}.MGRPMA WHERE SKUGRKY = #{param.skugrky} ) )
AND WS.ITEMCOD = #{param.itemcod}
AND UPPER(TRIM(WS.DEMODNM)) LIKE CONCAT('%', UPPER(TRIM(#{param.denamlc})), '%')
AND DATE_FORMAT(STR_TO_DATE(WS.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WS.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
AND WS.SKULENG >= #{param.skulengFrom}
AND WS.SKULENG <= #{param.skulengTo}
AND WS.SKUWEIG >= #{param.skuweigFrom}
AND WS.SKUWEIG <= #{param.skuweigTo}
AND WS.SKUWIDT >= #{param.skuwidtFrom}
AND WS.SKUWIDT <= #{param.skuwidtTo}
AND WS.EMSKUYN = #{param.emskuyn}
GROUP BY WS.STOCKKY,
WS.WAREKEY, WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER, WS.SAVEPNT, WS.LOTNMKY, WS.OWNERKY, WS.OWNRNAM, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY, WS.FCNAMLC, WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC, WS.STLOTNB, WS.GROSSWG, WS.GROSSLN, WS.GROSSWD, WS.GROSSTH, WS.BTRCATE, WS.BTRFSTC, WS.PURCNUM, WS.ORDERLN, WS.REGIKEY, WS.DESTKEY, WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DEORGNM, WS.DESTMOD, WS.ITEMCOD, WS.DEMODNM, WS.DEMODYN, WS.DEMDMAN, WS.DEMPOCD, WS.DEMDADR, WS.DEMDTLN, WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY, WS.SUOMKEY, WS.ADDCOKY, WS.POSHPDT, WS.POSHPTM, WS.POSHPDY, WS.SHPLIMT, WS.DELVDSR, WS.STKMEMO, WS.EMSKUYN, WS.RCVDCDT, WS.LOTAT01, WS.LOTAT02, WS.LOTAT03, WS.STKSTAT, WS.BLOCKID, WS.RCVDCKY, WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY, WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY, WS.TASKOIT, MR1.RENAMLC, MR2.RENAMLC,
MW.WHNAMLC, MA.AREANAM, ML.LOCANAM, MCO1.COMCDTX, WR.RCVDCDT, WR.RCVDCTM, MC02.COMCDTX,
WS.CREDATE, WS.CRETIME, WS.CREUSER, WS.LMODATE, WS.LMOTIME, WS.LMOUSER, WS.UPDTCHK ORDER BY WS.WAREKEY, WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER DESC

/* selectTargetStockListForValidation */ SELECT
WS.STOCKKY,
WS.WAREKEY, WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER, WS.SAVEPNT, WS.LOTNMKY, WS.OWNERKY, WS.OWNRNAM, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY, WS.FCNAMLC, WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC, WS.STLOTNB, WS.GROSSWG, WS.GROSSLN, WS.GROSSWD, WS.GROSSTH, WS.BTRCATE, WS.BTRFSTC, WS.PURCNUM, WS.ORDERLN, WS.REGIKEY, WS.DESTKEY, WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DEORGNM, WS.DESTMOD, WS.ITEMCOD, WS.DEMODNM, WS.DEMODYN, WS.DEMDMAN, WS.DEMPOCD, WS.DEMDADR, WS.DEMDTLN, WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY, WS.SUOMKEY, WS.ADDCOKY, WS.POSHPDT, WS.POSHPTM, WS.POSHPDY, WS.SHPLIMT, WS.DELVDSR, WS.STKMEMO, WS.EMSKUYN, WS.RCVDCDT, WS.RCVDCTM, WS.LOTAT01, WS.LOTAT02, WS.LOTAT03, WS.STKSTAT, WS.BLOCKID, WS.RCVDCKY, WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY, WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY, WS.TASKOIT, DATE_FORMAT(WS.CREDATE, '%Y-%m-%d') AS CREDATE, DATE_FORMAT(STR_TO_DATE(WS.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WS.CREUSER) AS CREUSER, DATE_FORMAT(WS.LMODATE, '%Y-%m-%d') AS LMODATE, DATE_FORMAT(STR_TO_DATE(WS.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER, WS.UPDTCHK FROM ${userData.schema}.WSTKKY WS WHERE WS.STOTQTY > 0 AND WS.SALLQTY = 0 AND WS.SBLOQTY = 0 AND WS.PLANQTY = 0 AND WS.PLCMQTY = 0 AND WS.TASKQTY = 0
AND WS.WAREKEY IN
#{stock.warekey}
AND WS.SKUMKEY IN
#{stock.skumkey}
AND WS.REGIMOD = #{targetValue.regikey}
AND WS.DESTMOD = #{targetValue.destkey}
AND WS.OWNERKY = #{targetValue.ownerky}
AND UPPER(TRIM(WS.DEMODNM)) = UPPER(TRIM(#{targetValue.denamlc}))
AND UPPER(TRIM(WS.DEMDADR)) LIKE CONCAT('%', UPPER(TRIM(#{targetValue.desaddr})), '%')

/* doe045StockList */ SELECT CONCAT(WS.STOCKKY, WS.WAREKEY) as ROWKEY , WS.STOCKKY , WS.WAREKEY, WS.AREAKEY, MA.AREANAM , WS.LOCAKEY, ML.LOCANAM, WS.LOLAYER , WS.LOTNMKY, WS.OWNERKY, WS.SKUGRKY , WS.REGIORG, WS.DESTORG, WS.REGIMOD, WS.DESTMOD , WS.SKUMKEY, WS.SKUDESC, WS.SKUWEIG , WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC , WS.GROSSWG, WS.GROSSWD, WS.GROSSLN, WS.GROSSTH , WS.BTRCATE, WS.STLOTNB, WS.PURCNUM, WS.ORDERLN , WS.ITEMCOD, WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY , WS.SUOMKEY, WS.ADDCOKY, DATE_FORMAT(WS.RCVDCDT, '%Y-%m-%d') as RCVDCDT , WS.LOTAT01, WS.LOTAT02, WS.LOTAT03 , WS.STKSTAT, MCO.COMCDTX as STATNAM, WS.BLOCKID, WS.EMSKUYN, WS.STKMEMO , WS.RCVDCKY, WS.RCVDCIT , WS.ADJSOKY, WS.ADJSOIT , WS.PHYSOKY, WS.PHYSOIT , WS.SHPDCKY, WS.SHPDCIT , WS.TASKOKY, WS.TASKOIT, WS.CUSTNAM, WS.CUSTCOD, WS.DEMDMAN, WS.FCNAMLC , WS.DEORGNM, WS.DEMODNM, WS.DEMDADR, WS.DEMPOCD AS DEMPOCD, WS.DEMDTLN , WS.DEMODYN , DATE_FORMAT(WS.CREDATE, '%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WS.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WS.CREUSER) AS CREUSER , DATE_FORMAT(WS.LMODATE, '%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WS.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER , WS.UPDTCHK FROM ${userData.schema}.WSTKKY WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.AREAKEY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WS.WAREKEY AND ML.AREAKEY = WS.AREAKEY AND ML.LOCAKEY = WS.LOCAKEY AND ML.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MCO ON MCO.COMCDVL = WS.STKSTAT AND MCO.COMCDKY = 'STKSTAT' AND MCO.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.WRCVIT WR ON WR.RCVDCKY = WS.RCVDCKY AND WR.RCVDCIT = WS.RCVDCIT WHERE WS.WAREKEY = #{param.warekey} AND WS.STOTQTY > 0 AND WS.SALLQTY = 0 AND WS.SBLOQTY = 0 AND WS.PLANQTY = 0 AND WS.PLCMQTY = 0 AND WS.TASKQTY = 0 AND WS.STKSTAT = '00'
AND WS.CUSTCOD = #{param.custcod}
AND UPPER(TRIM(WS.CUSTCOD)) LIKE CONCAT('%', UPPER(TRIM(#{param.custnam})), '%')
AND UPPER(TRIM(WS.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND UPPER(TRIM(WS.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND UPPER(TRIM(WS.PURCNUM)) LIKE CONCAT('%', UPPER(TRIM(#{param.purcnum})), '%')
AND UPPER(TRIM(WS.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND UPPER(TRIM(WS.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WS.REGIMOD = #{param.regikey}
AND WS.DESTMOD = #{param.destkey}
AND WS.ITEMCOD = #{param.itemcod}
AND UPPER(TRIM(WS.DEMODNM)) LIKE CONCAT('%', UPPER(TRIM(#{param.denamlc})), '%')
AND DATE_FORMAT(STR_TO_DATE(WS.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WS.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
AND WS.SKULENG >= #{param.skulengFrom}
AND WS.SKULENG <= #{param.skulengTo}
AND WS.SKUWEIG >= #{param.skuweigFrom}
AND WS.SKUWEIG <= #{param.skuweigTo}
AND WS.SKUWIDT >= #{param.skuwidtFrom}
AND WS.SKUWIDT <= #{param.skuwidtTo}
AND WS.EMSKUYN = #{param.emskuyn}
ORDER BY WS.WAREKEY , WS.AREAKEY , WS.LOCAKEY , WS.LOLAYER DESC

mapper.insert:
/* saveDoe045Wplnhd */
INSERT INTO
	${userData.schema}.WPLNHD(
		SHPPLKY
		, WAREKEY, OWNERKY, REGIKEY, DESTKEY
		, DENAMLC, DESADDR, SHPWEIG, REMWEIG
		, SKUGRKY, WPLDATE, WPLTIME, DOCCATE
		, DOCTYPE, WPLSTAT, RSNCODE, PARSNNM
		, CREDATE, CRETIME, CREUSER
		, LMODATE, LMOTIME, LMOUSER
	)
VALUES(
		#{param.shpplky}
		, #{param.warekey}, #{param.ownerky}, #{param.regikey}, #{param.destkey}
		, #{param.denamlc}, #{param.desaddr}, #{param.shpweig}, #{param.remweig}
		, #{param.skugrky}, #{param.wpldate}, #{param.wpltime}, #{param.doccate}
		, #{param.doctype}, #{param.wplstat}, #{param.rsncode}, #{param.parsnnm}
	, date_format(now(), '%Y%m%d'), date_format(now(), '%H%i%s'), #{userData.useract}
	, date_format(now(), '%Y%m%d'),	date_format(now(), '%H%i%s'), #{userData.useract}
)

/* insertTplnitForAddStock */
INSERT INTO ${userData.schema}.TPLNIT ( WAREKEY, VHPLNKY, VHPLNIT, CUSTCOD, OWNERKY, CUSTNAM, OWNRNAM, SKUMKEY, SKUDESC, OBITQTY, TRITQTY, REGIORG, REGIMOD, DESTORG, DEORGNM, DESTMOD, DEMODNM, DEMDMAN, DEMPOCD, DEMDADR, DEMDTLN, ITEMCOD, SKUGRKY, SKUTHIC, SKUWIDT, SKULENG, SKUWEIG, STKMEMO, GROSSWD, GROSSLN, GROSSTH, GROSSWG, PURCNUM, ORDERLN, SUOMKEY, EMSKUYN, SHPPLKY, SHPPLIT, BTRCATE, ADDCOKY, POSHPDT, POSHPTM, POSHPDY, SHPLIMT, DELVDSR, BTRFSTC, PLNSIZE, FNCUSKY, FCNAMLC, LOTAT01, LOTAT02, LOTAT03, STLOTNB, RCVDCKY, RCVDCIT, RCVDCDT, RCVDCTM, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER ) VALUES ( #{param.warekey}, #{param.vhplnky}, ${userData.schema}.FN_TM_VHPLNIT(#{param.vhplnky}), #{stock.custcod}, #{stock.ownerky}, #{stock.custnam}, #{stock.ownrnam}, #{stock.skumkey}, #{stock.skudesc}, 1, 1, #{stock.regiorg}, #{stock.regimod}, #{stock.destorg}, #{stock.deorgnm}, #{stock.destmod}, #{stock.demodnm}, #{stock.demdman}, #{stock.dempocd}, #{stock.demdadr}, #{stock.demdtln}, #{stock.itemcod}, #{stock.skugrky}, #{stock.skuthic}, #{stock.skuwidt}, #{stock.skuleng}, #{stock.skuweig}, #{stock.stkmemo}, #{stock.grosswd}, #{stock.grossln}, #{stock.grossth}, #{stock.grosswg}, #{stock.purcnum}, #{stock.orderln}, #{stock.suomkey}, #{stock.emskuyn}, #{param.shpplky}, (SELECT A.SHPPLIT FROM ${userData.schema}.WPLNIT A WHERE A.WAREKEY = #{param.warekey} AND A.SKUMKEY = #{stock.skumkey} AND A.SHPPLKY = #{param.shpplky}), #{stock.btrcate}, #{stock.addcoky}, #{stock.poshpdt}, #{stock.poshptm}, #{stock.poshpdy}, #{stock.shplimt}, #{stock.delvdsr}, #{stock.btrfstc}, #{param.plnsize}, #{stock.fncusky}, #{stock.fcnamlc}, #{stock.lotat01}, #{stock.lotat02}, #{stock.lotat03}, #{stock.stlotnb}, #{stock.rcvdcky}, #{stock.rcvdcit}, #{stock.rcvdcdt}, #{stock.rcvdctm},
DATE_FORMAT(NOW(), '%Y%m%d'), DATE_FORMAT(NOW(), '%H%i%s'), #{userData.useract}, DATE_FORMAT(NOW(), '%Y%m%d'), DATE_FORMAT(NOW(), '%H%i%s'), #{userData.useract} )

/* insertOoubitForAddStock */

INSERT INTO
	${userData.schema}.OOUBIT(
		OUTBOKY, OUTBOIT, DOCCATE, DOCTYPE
		, WAREKEY, OWNERKY, CUSTCOD, REGIORG
		, DESTORG, REGIMOD, DESTMOD, OBOMEMO
		, OUBRQDT, OUBRQTM, SKUGRKY, SKUMKEY
		, SKUDESC
		, SKUWEIG, SKUWIDT, SKULENG, SKUTHIC
		, GROSSWG, GROSSWD, GROSSLN, GROSSTH
		, FRAREKY, FRLOCKY, FRLAYER
		, SHLOCKY, EQUIPKY
		, RGITQTY, SUOMKEY, SHPPLKY, SHPPLIT, VHPLNKY
		, VHPLNIT, OBOITST, ITEMCOD, PURCNUM, ORDERLN
		, STLOTNB, SHPLIMT, DELVDSR, BTRFSTC, PARSNCD, PARSNNM
		, PLNSIZE, BTRCATE, ADDCOKY
		, POSHPDT, POSHPTM, POSHPDY
		, OWNRNAM, CUSTNAM, FNCUSKY
		, DEMODYN, DEMDMAN, DEMDADR, DEMPOCD, DEMDTLN
		, DEORGNM, DEMODNM
		, RCVDCKY, RCVDCIT, RCVDCDT, RCVDCTM
		, CREDATE, CRETIME, CREUSER
		, LMODATE, LMOTIME, LMOUSER
	)
VALUES
(
	#{param.outboky}, ${userData.schema}.FN_OM_OUTBOIT(#{param.outboky}), #{param.doccate}, #{param.doctype}
	, #{param.warekey}, #{stock.ownerky}, #{stock.custcod}, #{stock.regiorg}
	, #{stock.destorg}, #{stock.regimod}, #{stock.destmod}, ''
	, '', '', #{stock.skugrky}, #{stock.skumkey}
	, #{stock.skudesc}
	, #{stock.skuweig}, #{stock.skuwidt}, #{stock.skuleng}, #{stock.skuthic}
	, #{stock.grosswg}, #{stock.grosswd}, #{stock.grossln}, #{stock.grossth}
	, #{stock.areakey}, #{stock.locakey}, #{stock.lolayer}
	, (	SELECT
			A.LOCAKEY
		FROM
			${userData.schema}.MEQLOC A
		INNER JOIN
			${userData.schema}.MLOCMA B
		ON A.WAREKEY = B.WAREKEY
			AND A.AREAKEY = B.AREAKEY
			AND A.LOCAKEY = B.LOCAKEY
		WHERE
			A.WAREKEY = #{stock.warekey}
			AND A.AREAKEY = #{stock.areakey}
			AND A.EQUIPKY = #{stock.equipky}
			AND A.ELUSEYN = 'Y'
			AND B.LOCTYPE = 'STP'
			AND B.LOUSEYN = 'Y'
		GROUP BY
			A.LOCAKEY
		ORDER BY
			A.WAREKEY, A.AREAKEY, A.EQUIPKY,
			A.MANEQYN DESC
		LIMIT 1
	), #{stock.equipky}
	, 1, #{stock.suomkey}, #{param.shpplky}, (SELECT SHPPLIT FROM ${userData.schema}.WPLNIT WHERE WAREKEY = #{param.warekey} AND SKUMKEY = #{stock.skumkey} AND SHPPLKY = #{param.shpplky}), #{param.vhplnky}
	, (SELECT VHPLNIT FROM ${userData.schema}.TPLNIT WHERE WAREKEY = #{param.warekey} AND SKUMKEY = #{stock.skumkey} AND VHPLNKY = #{param.vhplnky}), 'NEW', #{stock.itemcod}, #{stock.purcnum}, #{stock.orderln}
	, #{stock.stlotnb}, #{stock.shplimt}, #{stock.delvdsr}, #{stock.btrfstc}, #{stock.parsncd}, #{stock.parsnnm}
	, #{param.plnsize}, #{stock.btrcate}, #{stock.addcoky}
	, #{stock.poshpdt}, #{stock.poshptm}, #{stock.poshpdy}
	, #{stock.ownrnam}, #{stock.custnam}, #{stock.fncusky}
	, #{stock.demodyn}, #{stock.demdman}, #{stock.demdadr}, #{stock.dempocd}, #{stock.demdtln}
	, #{stock.deorgnm}, #{stock.demodnm}
	, #{stock.rcvdcky}, #{stock.rcvdcit}, #{stock.rcvdcdt}, #{stock.rcvdctm}
	, date_format(now(), '%Y%m%d'), date_format(now(), '%H%i%s'), #{userData.useract}
	, date_format(now(), '%Y%m%d'), date_format(now(), '%H%i%s'), #{userData.useract}
)

mapper.select:
/* selectWplnhdListForVerification */ SELECT
WPH.SHPPLKY,
WPH.WAREKEY, WPH.OWNERKY, WPH.REGIKEY, WPH.DESTKEY, WPH.DENAMLC, WPH.DESADDR, WPH.SHPWEIG, WPH.REMWEIG, WPH.SKUGRKY, WPH.WPLDATE, WPH.WPLTIME, WPH.DOCCATE, WPH.DOCTYPE, WPH.WPLSTAT, WPH.RSNCODE, WPH.PARSNNM,
WPH.CREDATE, WPH.CRETIME, WPH.CREUSER, WPH.LMODATE, WPH.LMOTIME, WPH.LMOUSER, WPH.UPDTCHK FROM ${userData.schema}.WPLNHD WPH
AND WPH.WAREKEY = #{param.warekey}
AND WPH.SHPPLKY = #{param.shpplky}
GROUP BY
WPH.SHPPLKY,
WPH.WAREKEY, WPH.REGIKEY, WPH.SHPWEIG, WPH.REMWEIG, WPH.SKUGRKY, WPH.WPLDATE, WPH.WPLTIME, WPH.DOCCATE, WPH.DOCTYPE, WPH.WPLSTAT, WPH.RSNCODE, WPH.PARSNNM,
WPH.CREDATE, WPH.CRETIME, WPH.CREUSER, WPH.LMODATE, WPH.LMOTIME, WPH.LMOUSER, WPH.UPDTCHK

/* selectWplnitListForVerification */ SELECT
WPI.SHPPLKY, WPI.SHPPLIT, WPI.WPLITST, WPI.DOCCATE, WPI.DOCTYPE, WPI.WAREKEY, WPI.POSHPDT, WPI.POSHPTM, WPI.POSHPDY, WPI.OWNERKY, WPI.STOCKKY, WPI.REGIORG, WPI.DESTORG, WPI.SKUGRKY, WPI.REGIMOD, WPI.CUSTCOD, WPI.CUSTNAM, WPI.OWNRNAM, WPI.FNCUSKY, WPI.DESTMOD, WPI.DEMDMAN, WPI.DEMODNM, WPI.DEMODYN, WPI.DEMDADR, WPI.DEMPOCD, WPI.DEMDTLN, WPI.SKUMKEY, WPI.SKUDESC, WPI.TPRILOC, WPI.SPRILOC, WPI.EMSKUYN, WPI.CHKDISP, WPI.SKUWEIG, WPI.SKUWIDT, WPI.SKULENG, WPI.SKUTHIC, WPI.GROSSWD, WPI.GROSSLN, WPI.GROSSTH, WPI.GROSSWG, WPI.PLANQTY, WPI.SUOMKEY, WPI.ITEMCOD, WPI.STLOTNB, WPI.PURCNUM, WPI.ORDERLN, WPI.SHPLIMT, WPI.DELVDSR, WPI.BTRFSTC, WPI.BTRCATE, WPI.ADDCOKY,
DATE_FORMAT(STR_TO_DATE(WPI.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WPI.CREUSER) AS CREUSER, DATE_FORMAT(WPI.LMODATE, '%Y-%m-%d') AS LMODATE, DATE_FORMAT(STR_TO_DATE(WPI.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WPI.LMOUSER) AS LMOUSER, WPI.UPDTCHK FROM ${userData.schema}.WPLNIT WPI
AND WPI.WAREKEY = #{param.warekey}
AND WPI.SHPPLKY = #{param.shpplky}
AND WPI.SHPPLIT = #{param.shpplit}
GROUP BY WPI.SHPPLKY, WPI.SHPPLIT, WPI.WPLITST, WPI.DOCCATE, WPI.DOCTYPE, WPI.WAREKEY, WPI.POSHPDT, WPI.POSHPTM, WPI.POSHPDY, WPI.OWNERKY, WPI.STOCKKY, WPI.REGIORG, WPI.DESTORG, WPI.SKUGRKY, WPI.REGIMOD, WPI.CUSTCOD, WPI.CUSTNAM, WPI.OWNRNAM, WPI.FNCUSKY, WPI.DESTMOD, WPI.DEMDMAN, WPI.DEMODNM, WPI.DEMODYN, WPI.DEMDADR, WPI.DEMPOCD, WPI.DEMDTLN, WPI.SKUMKEY, WPI.SKUDESC, WPI.TPRILOC, WPI.SPRILOC, WPI.EMSKUYN, WPI.CHKDISP, WPI.SKUWEIG, WPI.SKUWIDT, WPI.SKULENG, WPI.SKUTHIC, WPI.GROSSWD, WPI.GROSSLN, WPI.GROSSTH, WPI.GROSSWG, WPI.PLANQTY, WPI.SUOMKEY, WPI.ITEMCOD, WPI.STLOTNB, WPI.PURCNUM, WPI.ORDERLN, WPI.SHPLIMT, WPI.DELVDSR, WPI.BTRFSTC, WPI.BTRCATE, WPI.ADDCOKY,
WPI.CREDATE, WPI.CRETIME, WPI.CREUSER, WPI.LMODATE, WPI.LMOTIME, WPI.LMOUSER, WPI.UPDTCHK

/* selectWplnitList */ SELECT
WPI.SHPPLKY, WPI.SHPPLIT,
WPI.DOCCATE, WPI.DOCTYPE, WPI.WAREKEY, WPI.POSHPDT, WPI.POSHPTM, WPI.POSHPDY, WPI.OWNERKY, WPI.STOCKKY, WPI.REGIORG, WPI.DESTORG, WPI.SKUGRKY, WPI.REGIMOD, WPI.CUSTCOD, WPI.CUSTNAM, WPI.OWNRNAM, WPI.FNCUSKY, WPI.DESTMOD, WPI.DEMDMAN, WPI.DEMODNM, WPI.DEMODYN, WPI.DEMDADR, WPI.DEMPOCD, WPI.DEMDTLN, WPI.SKUMKEY, WPI.SKUDESC, WPI.TPRILOC, WPI.SPRILOC, WPI.EMSKUYN, WPI.CHKDISP, WPI.SKUWEIG, WPI.SKUWIDT, WPI.SKULENG, WPI.SKUTHIC, WPI.GROSSWD, WPI.GROSSLN, WPI.GROSSTH, WPI.GROSSWG, WPI.PLANQTY, WPI.SUOMKEY, WPI.ITEMCOD, WPI.STLOTNB, WPI.PURCNUM, WPI.ORDERLN, WPI.SHPLIMT, WPI.DELVDSR, WPI.BTRFSTC, WPI.DEORGNM, WPI.BTRCATE, WPI.ADDCOKY, WPI.RCVDCDT, WPI.RCVDCTM, WPI.RCVDCKY, WPI.RCVDCIT,
DATE_FORMAT(WPI.CREDATE, '%Y-%m-%d') AS CREDATE, DATE_FORMAT(STR_TO_DATE(WPI.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(WPI.CREUSER) AS CREUSER, DATE_FORMAT(WPI.LMODATE, '%Y-%m-%d') AS LMODATE, DATE_FORMAT(STR_TO_DATE(WPI.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(WPI.LMOUSER) AS LMOUSER, WPI.UPDTCHK,
MW.WHNAMLC, MDC1.DOCCTNM, MDC1.DOCTYNM, MCD1.COMCDTX AS WPLITSN, MGR.GRPKYNM, MRE1.RENAMLC AS REORGNM, MRE2.RENAMLC AS REMODNM, MCD2.COMCDTX AS SUOMNAM, MCD3.COMCDTX AS WPLITST, BTC.BTRCNAM AS BTRCNAM, MCD4.COMCDTX AS ADDCNAM FROM ${userData.schema}.WPLNIT WPI INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WPI.WAREKEY INNER JOIN ${userData.schema}.MDOCMA MDC1 ON MDC1.WAREKEY = WPI.WAREKEY AND MDC1.DOCCATE = WPI.DOCCATE AND MDC1.DOCTYPE = WPI.DOCTYPE INNER JOIN ${userData.schema}.MCODEM MCD1 ON MCD1.COMCDKY = 'WPLITST' AND MCD1.COMCDVL = WPI.WPLITST INNER JOIN ${userData.schema}.MCODEM MCD2 ON MCD2.COMCDKY = 'SUOMKEY' AND MCD2.COMCDVL = WPI.SUOMKEY INNER JOIN ${userData.schema}.MCODEM MCD3 ON MCD3.COMCDKY = 'WPLITST' AND MCD3.COMCDVL = WPI.WPLITST INNER JOIN ${userData.schema}.MREGMA MRE1 ON MRE1.REGIKEY = WPI.REGIORG INNER JOIN ${userData.schema}.MREGMA MRE2 ON MRE2.REGIKEY = WPI.REGIMOD INNER JOIN ${userData.schema}.MGRPMA MGR ON MGR.SKUGRKY = WPI.SKUGRKY INNER JOIN ${userData.schema}.BTRCAT BTC ON BTC.BTRCATE = WPI.BTRCATE LEFT JOIN ( SELECT MC.COMCDTX, BC.ADDCOKY FROM ${userData.schema}.MCODEM MC INNER JOIN ${userData.schema}.BADDCO BC ON BC.ADDSIKY = MC.COMCDVL ) AS MCD4 ON MCD4.ADDCOKY = WPI.ADDCOKY
AND WPI.WAREKEY = #{param.warekey}
AND WPI.SHPPLKY = #{param.shpplky}
AND WPI.SHPPLIT = #{param.shpplit}
GROUP BY WPI.SHPPLKY, WPI.SHPPLIT,
WPI.DOCCATE, WPI.DOCTYPE, WPI.WAREKEY, WPI.POSHPDT, WPI.POSHPTM, WPI.POSHPDY, WPI.OWNERKY, WPI.STOCKKY, WPI.REGIORG, WPI.DESTORG, WPI.SKUGRKY, WPI.REGIMOD, WPI.CUSTCOD, WPI.CUSTNAM, WPI.OWNRNAM, WPI.FNCUSKY, WPI.DESTMOD, WPI.DEMDMAN, WPI.DEMODNM, WPI.DEMODYN, WPI.DEMDADR, WPI.DEMPOCD, WPI.DEMDTLN, WPI.SKUMKEY, WPI.SKUDESC, WPI.TPRILOC, WPI.SPRILOC, WPI.EMSKUYN, WPI.CHKDISP, WPI.SKUWEIG, WPI.SKUWIDT, WPI.SKULENG, WPI.SKUTHIC, WPI.GROSSWD, WPI.GROSSLN, WPI.GROSSTH, WPI.GROSSWG, WPI.PLANQTY, WPI.SUOMKEY, WPI.ITEMCOD, WPI.STLOTNB, WPI.PURCNUM, WPI.ORDERLN, WPI.SHPLIMT, WPI.DELVDSR, WPI.BTRFSTC, WPI.DEORGNM, WPI.BTRCATE, WPI.ADDCOKY, WPI.RCVDCDT, WPI.RCVDCTM, WPI.RCVDCKY, WPI.RCVDCIT,
WPI.CRETIME, WPI.CREUSER, WPI.LMODATE, WPI.LMOTIME, WPI.LMOUSER, WPI.UPDTCHK,
MW.WHNAMLC, MDC1.DOCCTNM, MDC1.DOCTYNM, MCD1.COMCDTX, MGR.GRPKYNM, MRE1.RENAMLC, MRE2.RENAMLC, MCD2.COMCDTX, MCD3.COMCDTX, BTC.BTRCNAM, MCD4.COMCDTX

/* selectDispatchedWplnhdList */ SELECT CONCAT(WP.SHPPLKY, WP.WAREKEY, TPW.VHPLNKY, TPW.PLNSIZE) AS ROWKEY , WP.WAREKEY, MW.WHNAMLC, TPW.VHPLNKY, TPW.PLNSIZE, MG.GRPKYNM AS PLNSZNM, WP.SHPPLKY , TP.VEHICKY, MV.VHCSNAM, MV.VHCFNAM, WP.SHPWEIG, (TPW.ALCWEIG * 1000) AS ALCWEIG, WP.REMWEIG , WP.WPLSTAT, MCW.COMCDTX AS WPLSTNM, WP.RSNCODE, WP.PARSNNM , DATE_FORMAT(WP.WPLDATE, '%Y-%m-%d') AS WPLDATE , CASE WHEN WP.WPLTIME IS NULL OR WP.WPLTIME = '' THEN '' ELSE STR_TO_DATE(WP.WPLTIME, '%H%i%s') END AS WPLTIME , TPW.REGIKEY, MR.RENAMLC, WP.DOCCATE, WP.DOCTYPE , MD.DOCTYNM, MD.DOCCTNM, MRC.RSNCDNM , DATE_FORMAT(WP.CREDATE, '%Y-%m-%d') AS CREDATE , CASE WHEN WP.CRETIME IS NULL OR WP.CRETIME = '' THEN '' ELSE STR_TO_DATE(WP.CRETIME, '%H%i%s') END AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WP.CREUSER) AS CREUSER , DATE_FORMAT(WP.LMODATE, '%Y-%m-%d') AS LMODATE , CASE WHEN WP.LMOTIME IS NULL OR WP.LMOTIME = '' THEN '' ELSE STR_TO_DATE(WP.LMOTIME, '%H%i%s') END AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WP.LMOUSER) AS LMOUSER , WP.UPDTCHK FROM ${userData.schema}.WPLNHD WP INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WP.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.TPWPWG TPW ON TPW.SHPPLKY = WP.SHPPLKY INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = TPW.PLNSIZE AND MG.GRUSEYN = 'Y' INNER JOIN ${userData.schema}.TPLNHD TP ON TP.VHPLNKY = TPW.VHPLNKY AND TP.WAREKEY = WP.WAREKEY INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VEHICKY = TP.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MCW ON MCW.COMCDKY = 'WPLSTAT' AND MCW.COMCDVL = WP.WPLSTAT AND MCW.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR ON MR.REGIKEY = TPW.REGIKEY AND MR.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.DOCCATE = WP.DOCCATE AND MD.DOCTYPE = WP.DOCTYPE INNER JOIN ${userData.schema}.MRSCMA MRC ON MRC.WAREKEY = WP.WAREKEY AND MRC.DOCCATE = WP.DOCCATE AND MRC.DOCTYPE = WP.DOCTYPE AND MRC.RSNCODE = WP.RSNCODE LEFT JOIN ${userData.schema}.WPLNIT WPI ON WP.SHPPLKY = WPI.SHPPLKY WHERE WP.WAREKEY = #{param.warekey} AND WP.WPLSTAT IN ('NEW', 'ING', 'CMP') AND TPW.WPLCFYN = 'N' AND TPW.OOUCFYN = 'N' AND TPW.SHPCFYN = 'N' AND TP.APROVYN = 'APPROVAL'
AND UPPER(TRIM(WP.SHPPLKY)) LIKE CONCAT ('%', UPPER(TRIM(#{param.shpplky})), '%')
AND UPPER(TRIM(TPW.VHPLNKY)) LIKE CONCAT ('%', UPPER(TRIM(#{param.vhplnky})), '%')
AND DATE_FORMAT(STR_TO_DATE(WP.WPLDATE, '%Y%m%d'), '%Y-%m-%d') >= #{param.wpldateFrom}
AND DATE_FORMAT(STR_TO_DATE(WP.WPLDATE, '%Y%m%d'), '%Y-%m-%d') <= #{param.wpldateTo}
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT ('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND UPPER(TRIM(WPI.DEMODNM)) LIKE CONCAT('%',UPPER(TRIM(#{param.demodnm})),'%')
AND UPPER(TRIM(WPI.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND (UPPER(TRIM(WPI.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%') OR (TRIM(#{param.skumkey}) = '' AND WPI.SKUMKEY IS NULL))
AND UPPER(TRIM(WPI.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND (UPPER(TRIM(WPI.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%') OR (TRIM(#{param.orderln}) = '' AND WPI.ORDERLN IS NULL))
AND DATE_FORMAT(STR_TO_DATE(WPI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WPI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
GROUP BY WP.WAREKEY, MW.WHNAMLC, TPW.VHPLNKY, TPW.PLNSIZE, MG.GRPKYNM , WP.SHPPLKY, TP.VEHICKY, MV.VHCSNAM, MV.VHCFNAM, WP.SHPWEIG , TPW.ALCWEIG, WP.REMWEIG, WP.WPLSTAT, MCW.COMCDTX, WP.RSNCODE , WP.PARSNNM, WP.WPLDATE, WP.WPLTIME, TPW.REGIKEY, MR.RENAMLC , WP.DOCCATE, WP.DOCTYPE, MD.DOCTYNM, MD.DOCCTNM, MRC.RSNCDNM , WP.CREDATE, WP.CRETIME, WP.CREUSER, WP.LMODATE, WP.LMOTIME , WP.LMOUSER, WP.UPDTCHK ORDER BY TPW.VHPLNKY DESC, WP.SHPPLKY DESC

