/* updateTpwpwgConfirmFlag */
UPDATE ${userData.schema}.TPWPWG
	SET WPLCFYN = #{status},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = UPDTCHK + 1
WHERE VHPLNKY = #{param.vhplnky}
  AND SHPPLKY = #{param.shpplky}
  AND PLNSIZE = #{param.plnsize}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${userData.schema}.TPWPWG WHERE VHPLNKY = #{param.vhplnky} AND SHPPLKY = #{param.shpplky} AND PLNSIZE = #{param.plnsize})

mapper.select:
/* selectDispatchedWplnitList */ SELECT MW.WHNAMLC, TPI.VHPLNKY, TPI.VHPLNIT, TPI.CUSTCOD , CASE WHEN TPI.CUSTCOD IS NULL OR TRIM(TPI.CUSTCOD) = '' THEN TPI.CUSTNAM WHEN MCU.CUNAMLC IS NULL OR TRIM(MCU.CUNAMLC) = '' THEN TPI.CUSTNAM ELSE MCU.CUNAMLC END AS CUSTNAM , TPI.WAREKEY, TPI.REGIORG, MRO.RENAMLC AS RONAMLC, TPI.REGIMOD, MR.RENAMLC AS RENAMLC , TPI.DESTORG , CASE WHEN TPI.DESTORG IS NULL OR TRIM(TPI.DESTORG) = '' THEN TPI.DEORGNM WHEN MDO.DENAMLC IS NULL OR TRIM(MDO.DENAMLC) = '' THEN TPI.DEORGNM ELSE MDO.DENAMLC END AS DEORGNM , TPI.DESTMOD , CASE WHEN TPI.DESTMOD IS NULL OR TRIM(TPI.DESTMOD) = '' THEN TPI.DEMODNM WHEN MDM.DENAMLC IS NULL OR TRIM(MDM.DENAMLC) = '' THEN TPI.DEMODNM ELSE MDM.DENAMLC END AS DEMODNM , TPI.OWNERKY, TPI.OWNRNAM, TPI.PLNSIZE , TPI.TPISTAT, MC.COMCDTX AS TPISTNM, TPI.SKUGRKY, WI.STOCKKY, WI.WPLITST , MG.GRPKYNM, TPI.SKUMKEY, TPI.SKUDESC, TPI.OBITQTY , TPI.TRITQTY, TPI.SKUTHIC, TPI.SKUWIDT, TPI.SKULENG , TPI.SKUWEIG, TPI.GROSSTH, TPI.GROSSWD, TPI.GROSSLN , TPI.GROSSWG, TPI.ITEMCOD AS ITEMMLC, TPI.EMSKUYN , TPI.STKMEMO, TPI.PURCNUM, TPI.ORDERLN, TPI.BTRCATE, BT.BTRCNAM , TPI.ADDCOKY, MC2.COMCDTX AS ADDCNAM, TPI.BTRFSTC , TPI.SHPPLKY, TPI.SHPPLIT , TPI.EMSKUYN, TPI.SHPLIMT, TPI.DELVDSR , WI.RCVDCDT, WI.RCVDCTM, WI.RCVDCKY, WI.RCVDCIT , DATE_FORMAT(TPI.CREDATE, '%Y-%m-%d') AS CREDATE , CASE WHEN TPI.CRETIME IS NULL OR TPI.CRETIME = '' THEN '' ELSE STR_TO_DATE(TPI.CRETIME, '%H%i%s') END AS CRETIME , ${userData.schema}.FN_SY_USERNAM(TPI.CREUSER) AS CREUSER , DATE_FORMAT(TPI.LMODATE, '%Y-%m-%d') AS LMODATE , CASE WHEN TPI.LMOTIME IS NULL OR TPI.LMOTIME = '' THEN '' ELSE STR_TO_DATE(TPI.LMOTIME, '%H%i%s') END AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(TPI.LMOUSER) AS LMOUSER , TPI.UPDTCHK FROM ${userData.schema}.TPLNIT TPI INNER JOIN ${userData.schema}.MCODEM MC ON TPI.TPISTAT = MC.COMCDVL AND MC.COMCDKY = 'TPISTAT' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.WPLNIT WI ON WI.SHPPLKY = TPI.SHPPLKY AND WI.SHPPLIT = TPI.SHPPLIT INNER JOIN ${userData.schema}.MGRPMA MG ON TPI.SKUGRKY = MG.SKUGRKY AND MG.GRUSEYN = 'Y' INNER JOIN ${userData.schema}.MWARMA MW ON TPI.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = TPI.BTRCATE INNER JOIN ${userData.schema}.MREGMA MR ON MR.REGIKEY = TPI.REGIMOD AND MR.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MRO ON MRO.REGIKEY = TPI.REGIORG AND MR.REUSEYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MCU ON MCU.CUSTKEY = TPI.CUSTCOD AND MCU.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MDO ON MDO.REGIKEY = TPI.REGIORG AND MDO.CUSTKEY = TPI.OWNERKY AND MDO.DESTKEY = TPI.DESTORG LEFT JOIN ${userData.schema}.MDESMA MDM ON MDM.REGIKEY = TPI.REGIMOD AND MDM.CUSTKEY = TPI.OWNERKY AND MDM.DESTKEY = TPI.DESTMOD LEFT JOIN ( SELECT MCI.COMCDTX, BC.ADDCOKY FROM ${userData.schema}.MCODEM MCI INNER JOIN ${userData.schema}.BADDCO BC ON MCI.COMCDKY = 'ADDCOKY' AND BC.ADDSIKY = MCI.COMCDVL ) AS MC2 ON MC2.ADDCOKY = TPI.ADDCOKY
AND TPI.WAREKEY = #{param.warekey}
AND TPI.VHPLNKY = #{param.vhplnky}
AND TPI.SHPPLKY = #{param.shpplky}
AND TPI.PLNSIZE = #{param.plnsize}
GROUP BY MW.WHNAMLC, TPI.VHPLNKY, TPI.VHPLNIT, TPI.CUSTCOD, TPI.CUSTNAM , MCU.CUNAMLC, TPI.WAREKEY, TPI.REGIORG, MRO.RENAMLC, TPI.REGIMOD , MR.RENAMLC, TPI.DESTORG, TPI.DEORGNM, MDO.DENAMLC, TPI.DESTMOD , TPI.DEMODNM, MDM.DENAMLC, TPI.OWNERKY, TPI.OWNRNAM, TPI.PLNSIZE , TPI.TPISTAT, MC.COMCDTX, TPI.SKUGRKY, WI.STOCKKY, WI.WPLITST , MG.GRPKYNM, TPI.SKUMKEY, TPI.SKUDESC, TPI.OBITQTY, TPI.TRITQTY , TPI.SKUTHIC, TPI.SKUWIDT, TPI.SKULENG, TPI.SKUWEIG, TPI.GROSSTH , TPI.GROSSWD, TPI.GROSSLN, TPI.GROSSWG, TPI.ITEMCOD, TPI.EMSKUYN , TPI.STKMEMO, TPI.PURCNUM, TPI.ORDERLN, TPI.BTRCATE, BT.BTRCNAM , TPI.SHPPLKY, TPI.SHPPLIT, TPI.EMSKUYN, TPI.BTRFSTC, MC2.COMCDTX , TPI.SHPLIMT, TPI.DELVDSR , WI.RCVDCDT, WI.RCVDCTM, WI.RCVDCKY, WI.RCVDCIT , TPI.CREDATE, TPI.CRETIME, TPI.CREUSER , TPI.LMODATE, TPI.LMOTIME, TPI.LMOUSER, TPI.UPDTCHK

