/* updateWplnhdForDispatch */

UPDATE ${userData.schema}.WPLNHD
	SET
		PARSNNM = #{data.parsnnm}

		, RSNCODE = #{data.rsncode}


		, WPLDATE = #{data.wpldate}


		, WPLTIME = #{data.wpltime}

		, LMODATE = date_format(now(), '%Y%m%d')
		, LMOTIME = date_format(now(), '%H%i%s')
		, LMOUSER = #{userData.useract}
	WHERE
		WAREKEY = #{data.warekey}
		AND SHPPLKY = #{data.shpplky}
		AND UPDTCHK = #{data.updtchk}
		AND WPLSTAT NOT IN ('CMP', 'CANCEL')

