/* selectFullDispatchedOutboundPlanHeaderList */ SELECT CONCAT(WPH.WAREKEY, WPH.SHPPLKY, TW.VHPLNKY, TW.PLNSIZE) AS ROWKEY , WPH.WAREKEY, MW.WHNAMLC, WPH.SHPPLKY, WPH.DOCCATE , MD.DOCCTNM, WPH.DOCTYPE, MD.DOCTYNM, WPH.SHPWEIG , WPH.REMWEIG, WPH.WPLSTAT, MC.COMCDTX AS WPLSTNM , WPH.RSNCODE, MRS.RSNCDNM, WPH.PARSNNM, WPH.REGIKEY , MR.RENAMLC, WPH.WPLDATE, WPH.WPLTIME, TW.VHPLNKY , MV.VHCFNAM, WPH.OWNERKY, WPH.DESTKEY, WPH.DENAMLC , WPH.DESADDR, (TW.ALCWEIG * 1000) AS ALCWEIG, TW.PLNSIZE , MG.GRPKYNM AS PLNSZNM, DATE_FORMAT(WPH.CREDATE, '%Y-%m-%d') AS CREDATE , CASE WHEN WPH.CRETIME IS NULL OR WPH.CRETIME = '' THEN '' ELSE STR_TO_DATE(WPH.CRETIME, '%H%i%s') END AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WPH.CREUSER) AS CREUSER , DATE_FORMAT(WPH.LMODATE, '%Y-%m-%d') AS LMODATE , CASE WHEN WPH.LMOTIME IS NULL OR WPH.LMOTIME = '' THEN '' ELSE STR_TO_DATE(WPH.LMOTIME, '%H%i%s') END AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WPH.LMOUSER) AS LMOUSER , WPH.UPDTCHK FROM ${userData.schema}.WPLNHD WPH INNER JOIN ${userData.schema}.MWARMA MW ON WPH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON WPH.DOCCATE = MD.DOCCATE AND WPH.DOCTYPE = MD.DOCTYPE INNER JOIN ${userData.schema}.MCODEM MC ON WPH.WPLSTAT = MC.COMCDVL AND MC.COMCDKY = 'WPLSTAT' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR ON WPH.REGIKEY = MR.REGIKEY AND MR.REUSEYN = 'Y' INNER JOIN ${userData.schema}.TPWPWG TW ON WPH.SHPPLKY = TW.SHPPLKY AND WPH.REGIKEY = TW.REGIKEY LEFT JOIN ${userData.schema}.TPLNHD TH ON TW.VHPLNKY = TH.VHPLNKY AND WPH.WAREKEY = TH.WAREKEY INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = TW.PLNSIZE AND MG.GRUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON TH.VEHICKY = MV.VEHICKY AND TH.VOWNKEY = MV.VOWNKEY AND MV.VHUSEYN = 'Y' LEFT JOIN ${userData.schema}.WPLNIT WPI ON WPH.SHPPLKY = WPI.SHPPLKY INNER JOIN ${userData.schema}.MRSCMA MRS ON MRS.WAREKEY = WPH.WAREKEY AND MRS.DOCCATE = WPH.DOCCATE AND MRS.DOCTYPE = WPH.DOCTYPE AND MRS.RSNCODE = WPH.RSNCODE AND MRS.RSUSEYN = 'Y' WHERE WPH.WPLSTAT IN ('ING', 'CMP') AND TW.WPLCFYN = 'Y' AND TW.OOUCFYN = 'N' AND TW.SHPCFYN = 'N' AND TW.ARRIVYN = 'N'
AND WPH.WAREKEY = #{param.warekey}
AND WPH.SHPPLKY LIKE CONCAT('%', #{param.shpplky}, '%')
AND TH.VHPLNKY LIKE CONCAT('%', #{param.vhplnky}, '%')
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND DATE_FORMAT(STR_TO_DATE(WPH.WPLDATE, '%Y%m%d'), '%Y-%m-%d') >= #{param.wpldateFrom}
AND DATE_FORMAT(STR_TO_DATE(WPH.WPLDATE, '%Y%m%d'), '%Y-%m-%d') <= #{param.wpldateTo}
AND UPPER(TRIM(WPI.DEMODNM)) LIKE CONCAT('%',UPPER(TRIM(#{param.demodnm})),'%')
AND UPPER(TRIM(WPI.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND (UPPER(TRIM(WPI.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%') OR (TRIM(#{param.skumkey}) = '' AND WPI.SKUMKEY IS NULL))
AND UPPER(TRIM(WPI.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND (UPPER(TRIM(WPI.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%') OR (TRIM(#{param.orderln}) = '' AND WPI.ORDERLN IS NULL))
AND DATE_FORMAT(STR_TO_DATE(WPI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WPI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
GROUP BY WPH.WAREKEY, MW.WHNAMLC, WPH.SHPPLKY, WPH.DOCCATE , MD.DOCCTNM, WPH.DOCTYPE, MD.DOCTYNM, WPH.SHPWEIG , WPH.REMWEIG, WPH.WPLSTAT, MC.COMCDTX , WPH.RSNCODE, WPH.PARSNNM, WPH.REGIKEY, MR.RENAMLC , WPH.WPLDATE, WPH.WPLTIME, TW.VHPLNKY, MV.VHCFNAM , TW.ALCWEIG, TW.PLNSIZE, MG.GRPKYNM , WPH.CREDATE , WPH.CRETIME , WPH.CREUSER , WPH.LMODATE , WPH.LMOTIME , WPH.LMOUSER , WPH.UPDTCHK ORDER BY TW.VHPLNKY DESC, WPH.SHPPLKY DESC

