/* getDoe049HeadList */ SELECT CONCAT(WP.WAREKEY, TP.VHPLNKY, TPW.SHPPLKY, TPW.PLNSIZE) AS ROWKEY, WP.WAREKEY, MW.WHNAMLC, TP.VHPLNKY, TP.VEHICKY, MV.VHCFNAM , TP.VOWNKEY, MO.VONAMLC, TPW.SHPPLKY, TPW.PLNSIZE , WP.DOCCATE, MD.DOCCTNM, WP.DOCTYPE, MD.DOCTYNM , WP.OWNERKY, WP.DESTKEY, WP.DENAMLC, WP.DESADDR , (SELECT SUM(ALCWEIG) FROM ${userData.schema}.TPWPWG WHERE VHPLNKY = TPW.VHPLNKY AND WPLCFYN = 'Y' AND OOUCFYN = 'N') AS SHPWEIG , WP.WPLSTAT, MC.COMCDTX as TSTSNAM , DATE_FORMAT(WP.WPLDATE,'%Y-%m-%d') as WPLDATE , DATE_FORMAT(STR_TO_DATE(WP.WPLTIME,'%H%i%s'),'%H:%i:%s') as WPLTIME , DATE_FORMAT(TP.VHPDATE,'%Y-%m-%d') as VHPDATE , DATE_FORMAT(STR_TO_DATE(TP.VHPTIME,'%H%i%s'),'%H:%i:%s') as VHPTIME , MGP.GRPKYNM , DATE_FORMAT(WP.CREDATE, '%Y-%m-%d') AS CREDATE , CASE WHEN WP.CRETIME IS NULL OR WP.CRETIME = '' THEN '' ELSE STR_TO_DATE(WP.CRETIME, '%H%i%s') END AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WP.CREUSER) AS CREUSER , DATE_FORMAT(WP.LMODATE, '%Y-%m-%d') AS LMODATE , CASE WHEN WP.LMOTIME IS NULL OR WP.LMOTIME = '' THEN '' ELSE STR_TO_DATE(WP.LMOTIME, '%H%i%s') END AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WP.LMOUSER) AS LMOUSER , WP.UPDTCHK , TP.TPRILOC , (SELECT LOCANAM FROM ${userData.schema}.MLOCMA WHERE WAREKEY = #{param.warekey} AND LOCTYPE = 'STP' AND LOUSEYN = 'Y' AND LOCAKEY = TP.TPRILOC) AS TRLOCML , TP.SPRILOC , (SELECT LOCANAM FROM ${userData.schema}.MLOCMA WHERE WAREKEY = #{param.warekey} AND LOCTYPE = 'STP' AND LOUSEYN = 'Y' AND LOCAKEY = TP.SPRILOC) AS SRLOCML FROM ${userData.schema}.WPLNHD WP INNER JOIN ${userData.schema}.TPWPWG TPW ON TPW.SHPPLKY = WP.SHPPLKY AND TPW.WPLCFYN = 'Y' AND TPW.OOUCFYN = 'N' INNER JOIN ${userData.schema}.TPLNHD TP ON TP.VHPLNKY = TPW.VHPLNKY INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WP.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WP.WAREKEY AND MD.DOCCATE = WP.DOCCATE AND MD.DOCTYPE = WP.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WP.WPLSTAT AND MC.COMCDKY = 'WPLSTAT' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VOWNKEY = TP.VOWNKEY AND MV.VEHICKY = TP.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVOWMA MO ON MO.VOWNKEY = TP.VOWNKEY AND MO.VOUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGP ON MGP.SKUGRKY = TPW.PLNSIZE AND MGP.GRUSEYN = 'Y' LEFT JOIN ${userData.schema}.WPLNIT WPI ON WP.SHPPLKY = WPI.SHPPLKY WHERE WP.WAREKEY = #{param.warekey} AND TP.TPNSTAT = #{param.tpnstat} AND TP.APROVYN = #{param.aprovyn} AND WP.WPLSTAT IN ('ING', 'CMP')
AND UPPER(TRIM(TP.VHPLNKY)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhplnky})), '%')
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND DATE_FORMAT(STR_TO_DATE(TP.VHPDATE, '%Y%m%d'), '%Y-%m-%d') >= #{param.vhpdatefrom}
AND DATE_FORMAT(STR_TO_DATE(TP.VHPDATE, '%Y%m%d'), '%Y-%m-%d') <= #{param.vhpdateto}
AND UPPER(TRIM(WPI.DEMODNM)) LIKE CONCAT('%', UPPER(TRIM(#{param.demodnm})),'%')
AND UPPER(TRIM(WPI.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND (UPPER(TRIM(WPI.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%') OR (TRIM(#{param.skumkey}) = '' AND WPI.SKUMKEY IS NULL))
AND UPPER(TRIM(WPI.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND (UPPER(TRIM(WPI.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%') OR (TRIM(#{param.orderln}) = '' AND WPI.ORDERLN IS NULL))
AND DATE_FORMAT(STR_TO_DATE(WPI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WPI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
GROUP BY WP.WAREKEY, MW.WHNAMLC, TP.VHPLNKY, TP.VEHICKY, MV.VHCFNAM , TP.VOWNKEY, MO.VONAMLC, WP.SHPPLKY, TPW.PLNSIZE, WP.DOCCATE , MD.DOCCTNM, WP.DOCTYPE, MD.DOCTYNM, WP.WPLSTAT, MC.COMCDTX , WP.WPLDATE, WP.WPLTIME, TP.VHPDATE, TP.VHPTIME, MGP.GRPKYNM , WP.CREDATE, WP.CRETIME, WP.CREUSER, WP.LMODATE, WP.LMOTIME , WP.LMOUSER, WP.UPDTCHK ORDER BY TP.VHPLNKY DESC, WP.SHPPLKY DESC

/* getDoe049ItemList */ SELECT TP.WAREKEY, MW.WHNAMLC, TP.VHPLNKY, TP.VHPLNIT , TP.SHPPLKY, TP.SHPPLIT, TP.OWNERKY , CASE WHEN TP.OWNERKY IS NULL OR TRIM(TP.OWNERKY) = '' THEN TP.OWNRNAM WHEN CUO.CUNAMLC IS NULL OR TRIM(CUO.CUNAMLC) = '' THEN TP.OWNRNAM ELSE CUO.CUNAMLC END AS OWNRNAM , TP.CUSTCOD , CASE WHEN TP.CUSTCOD IS NULL OR TRIM(TP.CUSTCOD) = '' THEN TP.CUSTNAM WHEN CUC.CUNAMLC IS NULL OR TRIM(CUC.CUNAMLC) = '' THEN TP.CUSTNAM ELSE CUC.CUNAMLC END AS CUSTNAM , TP.SKUGRKY, TP.SKUMKEY, TP.SKUDESC, TP.SKUWEIG , TP.SKUWIDT, TP.SKULENG, TP.SKUTHIC, TP.GROSSWG , TP.GROSSWD, TP.GROSSLN, TP.GROSSTH, WS.AREAKEY AS FRAREKY , WS.LOCAKEY AS FRLOCKY, WS.LOLAYER AS FRLAYER , TP.BTRCATE, TP.PURCNUM, TP.ORDERLN , (SELECT BTRCNAM FROM ${userData.schema}.BTRCAT WHERE BTRCATE = TP.BTRCATE) AS BTRCNAM , TP.REGIORG, MRO.RENAMLC AS REORGNM, TP.REGIMOD, MRM.RENAMLC AS REMODNM , TP.DESTORG , CASE WHEN TP.DESTORG IS NULL OR TRIM(TP.DESTORG) = '' THEN TP.DEORGNM WHEN MDO.DENAMLC IS NULL OR TRIM(MDO.DENAMLC) = '' THEN TP.DEORGNM ELSE MDO.DENAMLC END AS DEORGNM , TP.DESTMOD , CASE WHEN TP.DESTMOD IS NULL OR TRIM(TP.DESTMOD) = '' THEN TP.DEMODNM WHEN MDM.DENAMLC IS NULL OR TRIM(MDM.DENAMLC) = '' THEN TP.DEMODNM ELSE MDM.DENAMLC END AS DEMODNM , WS.STOTQTY AS RGITQTY, TP.SUOMKEY, WS.STLOTNB, TP.ITEMCOD , DATE_FORMAT(TP.POSHPDT, '%Y-%m-%d') AS POSHPDT , CASE WHEN TP.POSHPTM IS NULL OR TP.POSHPTM = '' THEN '' ELSE STR_TO_DATE(TP.POSHPTM, '%H%i%s') END AS POSHPTM , TP.POSHPDY, DATE_FORMAT(TP.SHPLIMT, '%Y-%m-%d') AS SHPLIMT, DATE_FORMAT(TP.DELVDSR, '%Y-%m-%d') AS DELVDSR, WS.DEMODYN , TP.DEMDMAN, TP.DEMDADR, TP.DEMPOCD, TP.DEMDTLN, TP.STKMEMO , TP.ADDCOKY , MCB.COMCDTX AS ADDNAML , WI.RCVDCKY, WI.RCVDCIT, WI.RCVDCDT, WI.RCVDCTM , DATE_FORMAT(TP.CREDATE, '%Y-%m-%d') AS CREDATE , CASE WHEN TP.CRETIME IS NULL OR TP.CRETIME = '' THEN '' ELSE STR_TO_DATE(TP.CRETIME, '%H%i%s') END AS CRETIME , ${userData.schema}.FN_SY_USERNAM(TP.CREUSER) AS CREUSER , DATE_FORMAT(TP.LMODATE, '%Y-%m-%d') AS LMODATE , CASE WHEN TP.LMOTIME IS NULL OR TP.LMOTIME = '' THEN '' ELSE STR_TO_DATE(TP.LMOTIME, '%H%i%s') END AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(TP.LMOUSER) AS LMOUSER , TP.UPDTCHK , TP.PLNSIZE , TP.EMSKUYN , TP.BTRFSTC , MGP.GRPKYNM AS GRPKYNM FROM ${userData.schema}.TPLNIT TP INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = TP.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGP ON TP.SKUGRKY = MGP.SKUGRKY INNER JOIN ${userData.schema}.MREGMA MRO ON MRO.REGIKEY = TP.REGIORG AND MRO.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MRM ON MRM.REGIKEY = TP.REGIMOD AND MRM.REUSEYN = 'Y' INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = TP.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MCB ON MCB.COMCDKY = 'ADDSIKY' AND MCB.COMCDVL = BA.ADDSIKY AND MCB.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.WPLNIT WI ON WI.SHPPLKY = TP.SHPPLKY AND WI.SHPPLIT = TP.SHPPLIT AND WI.WAREKEY = TP.WAREKEY AND WI.SKUMKEY = TP.SKUMKEY LEFT JOIN ${userData.schema}.MCUSMA CUO ON CUO.CUSTKEY = TP.OWNERKY AND CUO.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA CUC ON CUC.CUSTKEY = TP.CUSTCOD AND CUC.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.WSTKKY WS ON WS.STOCKKY = WI.STOCKKY AND WS.SKUMKEY = WI.SKUMKEY LEFT JOIN ${userData.schema}.MDESMA MDO ON MDO.CUSTKEY = TP.OWNERKY AND MDO.REGIKEY = TP.REGIORG AND MDO.DESTKEY = TP.DESTORG LEFT JOIN ${userData.schema}.MDESMA MDM ON MDM.CUSTKEY = TP.OWNERKY AND MDM.REGIKEY = TP.REGIMOD AND MDM.DESTKEY = TP.DESTMOD WHERE TP.WAREKEY = #{param.warekey} AND TP.VHPLNKY = #{param.vhplnky}
AND TP.SHPPLKY = #{param.shpplky}
AND TP.PLNSIZE = #{param.plnsize}
AND TP.TPISTAT = #{param.tpistat}
GROUP BY TP.WAREKEY, MW.WHNAMLC, TP.VHPLNKY, TP.VHPLNIT , TP.SHPPLKY, TP.SHPPLIT, TP.OWNERKY, TP.OWNRNAM , CUO.CUNAMLC, TP.CUSTCOD, TP.CUSTNAM, CUC.CUNAMLC , TP.SKUGRKY, TP.SKUMKEY, TP.SKUDESC, TP.SKUWEIG , TP.SKUWIDT, TP.SKULENG, TP.SKUTHIC, TP.GROSSWG , TP.GROSSWD, TP.GROSSLN, TP.GROSSTH, WS.AREAKEY , WS.LOCAKEY, WS.LOLAYER, TP.BTRCATE, TP.PURCNUM , TP.ORDERLN, TP.REGIORG, MRO.RENAMLC, TP.REGIMOD , MRM.RENAMLC, TP.DESTORG, TP.DEORGNM, MDO.DENAMLC , TP.DESTMOD, TP.DEMODNM, MDM.DENAMLC, WS.STOTQTY , TP.SUOMKEY, WS.STLOTNB, TP.ITEMCOD, TP.POSHPDT , TP.POSHPTM, TP.POSHPDY, TP.SHPLIMT, TP.DELVDSR , WS.DEMODYN, TP.DEMDMAN, TP.DEMDADR, TP.DEMPOCD , TP.DEMDTLN, TP.STKMEMO , WI.RCVDCKY, WI.RCVDCIT, WI.RCVDCDT, WI.RCVDCTM ,TP.CREDATE, TP.CRETIME , TP.CREUSER, TP.LMODATE, TP.LMOTIME, TP.LMOUSER , TP.UPDTCHK, TP.PLNSIZE, TP.EMSKUYN, TP.BTRFSTC , MGP.GRPKYNM

