	, PARSNCD, PARSNNM, SHPWEIG
	, WPLNDAT, WPLNTIM, REGIKEY
	, OBODATE, OBOTIME
	, SHPSDAY, SHPSTIM
	, CREDATE, CRETIME, CREUSER
