/* updateObostat */ UPDATE ${userData.schema}.OOUBHD SET OBOSTAT = #{param.obostat}, RSNCODE = #{param.rsncode},
PARSNNM = #{param.parsnnm},
LMODATE = date_format(now(), '%Y%m%d'), LMOTIME = date_format(now(), '%H%i%s'), LMOUSER = #{userData.useract}, UPDTCHK = UPDTCHK + 1 WHERE OUTBOKY = #{param.outboky} AND OBOSTAT != 'CANCEL'

/* updateOboitst */
UPDATE ${userData.schema}.OOUBIT
	SET OBOITST = #{param.oboitst},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = UPDTCHK + 1
	WHERE
		OUTBOKY = #{param.outboky}

			AND OUTBOIT = #{param.outboit}

/* updateTasksts */
UPDATE ${userData.schema}.WTAKIT
	SET TASKSTS = #{param.tasksts},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = UPDTCHK + 1
	WHERE
		WAREKEY = #{param.warekey}
		AND TASKOKY = #{param.taskoky}
		AND TASKOIT = #{param.taskoit}

/* updateShpitst */
UPDATE ${userData.schema}.WSHPIT
	SET SHPITST = #{param.shpitst},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = UPDTCHK + 1
	WHERE
		WAREKEY = #{param.warekey}
		AND SHPDCKY = #{param.shpdcky}

			AND SHPDCIT = #{param.shpdcit}

		AND SHPITST != 'CANCEL'

