AND OBOITST = #{param.oboitst}
GROUP BY OUTBOKY, OUTBOIT, DOCCATE, DOCTYPE , WAREKEY, POSHPDT, POSHPTM, POSHPDY , OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM , FNCUSKY, REGIORG, DESTORG, REGIMOD , DESTMOD, DEMODNM, DEMODYN, DEMDMAN , DEMDADR, DEMPOCD, DEMDTLN, OBOMEMO , OUBRQDT, OUBRQTM, SKUGRKY, SKUMKEY , SKUDESC, SKUWEIG, SKUWIDT, SKULENG , SKUTHIC, GROSSWG, GROSSWD, GROSSLN , GROSSTH, FRAREKY, FRLOCKY, FRLAYER , SHLOCKY, RGITQTY, SHCFQTY, SUOMKEY , SHPPLKY, SHPPLIT, VHPLNKY, VHPLNIT , OBOITST, ITEMCOD, PURCNUM, ORDERLN , STLOTNB, SHPLIMT, DELVDSR, BTRFSTC , BTRCATE, ADDCOKY , PARSNCD, PARSNNM, CREDATE, CRETIME , CREUSER, LMODATE, LMOTIME, LMOUSER , UPDTCHK

/* getDoe051HeadList */ SELECT WT.TASKOKY, WT.WAREKEY, MW.WHNAMLC, DATE_FORMAT(WT.TASKDAT, '%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , COUNT(WT.TASKOKY) as TOTITEM , SUM(OI.GROSSWG) as TOTWEIG , DATE_FORMAT(WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER), WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.OOUBIT OI ON OI.OUTBOKY = WT.OUTBOKY AND OI.OUTBOIT = WT.OUTBOIT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' WHERE WT.WAREKEY = #{param.warekey} AND WT.DOCCATE = #{param.doccate}
AND WT.TASKOKY = #{param.taskoky}
AND DATE_FORMAT(STR_TO_DATE(WT.TASKDAT, '%Y%m%d'), '%Y-%m-%d') >= #{param.taskdatfrom}
AND DATE_FORMAT(STR_TO_DATE(WT.TASKDAT, '%Y%m%d'), '%Y-%m-%d') <= #{param.taskdatto}
AND TASKSTS != #{param.tasksts}
GROUP BY WT.TASKOKY, WT.WAREKEY, WT.TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.CRETIME , WT.CREUSER , WT.LMODATE , WT.LMOTIME , WT.LMOUSER , WT.UPDTCHK

/* getDoe051ItemList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, MC.COMCDTX as TSTSNAM, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, MA1.AREANAM as FRARANM, WT.FRLOCKY, ML1.LOCANAM as FRLOCNM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM as TOARANM, WT.TOLOCKY, ML2.LOCANAM as TOLOCNM, WT.TOLAYER , WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WT.TASKSTS AND MC.COMCDKY = 'TASKSTS' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MCUSMA MCU1 ON MCU1.CUSTKEY = WT.OWNERKY AND MCU1.CUDELYN = 'Y' INNER JOIN ${userData.schema}.MCUSMA MCU2 ON MCU2.CUSTKEY = WT.CUSTCOD AND MCU2.CUDELYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = WT.WAREKEY AND MA1.AREAKEY = WT.FRAREKY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA2 ON MA2.WAREKEY = WT.WAREKEY AND MA2.AREAKEY = WT.TOAREKY AND MA2.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WT.WAREKEY AND ML1.AREAKEY = WT.FRAREKY AND ML1.LOCAKEY = WT.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WT.WAREKEY AND ML2.AREAKEY = WT.TOAREKY AND ML2.LOCAKEY = WT.TOLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.WSTKKY WS ON WS.WAREKEY = WT.WAREKEY AND WS.STOCKKY = WT.STOCKKY WHERE WT.WAREKEY = #{param.warekey}
AND WT.TASKOKY = #{param.taskoky}
AND TASKSTS != #{param.tasksts}
GROUP BY WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , WT.TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, MC.COMCDTX, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, MA1.AREANAM, WT.FRLOCKY, ML1.LOCANAM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM, WT.TOLOCKY, ML2.LOCANAM, WT.TOLAYER , WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , WT.CREDATE , WT.CRETIME , WT.CREUSER , WT.LMODATE , WT.LMOTIME , WT.LMOUSER , WT.UPDTCHK

