OBH.CREDATE, OBH.CRETIME, OBH.CREUSER, OBH.LMODATE, OBH.LMOTIME, OBH.LMOUSER, OBH.UPDTCHK FROM ${userData.schema}.OOUBHD OBH INNER JOIN ${userData.commonSchema}.MVHCMA MVH ON MVH.VOWNKEY = OBH.VOWNKEY AND MVH.VEHICKY = OBH.VEHICKY WHERE OBH.WAREKEY = #{param.warekey} AND OBH.OUTBOKY = #{param.outboky}

