/* updateEntdate */ UPDATE ${userData.schema}.OOUBHD OOU INNER JOIN ${userData.schema}.MWARMA MWA ON MWA.WAREKEY = OOU.WAREKEY SET OOU.ENTDOYN = IF(MWA.CNTRLYN = 'Y', 'N', 'Y'), OOU.ENTDATE = date_format(REPLACE(#{param.entdate}, '-', ''), '%Y%m%d'), OOU.ENTTIME = date_format(STR_TO_DATE(REPLACE(#{param.enttime}, ':', ''),'%H%i%s'), '%H%i%s'),
OOU.OBOSTAT = #{param.obostat},
ENTDOYN = 'Y', OOU.LMODATE = date_format(now(), '%Y%m%d'), OOU.LMOTIME = date_format(now(), '%H%i%s'), OOU.LMOUSER = #{userData.useract}, OOU.UPDTCHK = OOU.UPDTCHK + 1 WHERE OOU.WAREKEY = #{param.warekey} AND OOU.OUTBOKY = #{param.outboky}

/* updateDoe053Entdate */ UPDATE ${userData.schema}.OOUBHD SET ENTDATE = date_format(IF(ISNULL(#{param.entdate}) OR TRIM(#{param.entdate}) = '', now(), #{param.entdate}), '%Y%m%d'), ENTTIME = IF(ISNULL(#{param.enttime}), date_format(now(), '%H%i%s'), date_format(STR_TO_DATE(#{param.enttime},'%H:%i:%s'), '%H%i%s')),
OBOSTAT = #{param.obostat},
LMODATE = date_format(now(), '%Y%m%d'), LMOTIME = date_format(now(), '%H%i%s'), LMOUSER = #{userData.useract}, UPDTCHK = #{param.updtchk} + 1 WHERE OUTBOKY = #{param.outboky} AND UPDTCHK = #{param.updtchk}

mapper.select:
/* getDoe053HeadList */ SELECT OH.OUTBOKY, OH.WAREKEY, MW.WHNAMLC , OH.VOWNKEY, MO.VONAMLC, OH.VEHICKY, MV.VHCFNAM , OH.DOCCATE, MD.DOCCTNM, OH.DOCTYPE, MD.DOCTYNM , OH.RSNCODE, MR.RSNCDNM, OH.PARSNNM, OH.SHPWEIG , TWG.SHPPLKY, OH.VHPLNKY, OH.ENTDOYN , OH.TPRILOC AS TRLOCML, OH.SPRILOC AS SRLOCML , DATE_FORMAT(OH.OBODATE,'%Y-%m-%d') as OBODATE, DATE_FORMAT(STR_TO_DATE(OH.OBOTIME,'%H%i%s'),'%H:%i:%s') as OBOTIME , OH.OBOSTAT, MC.COMCDTX as TSTSNAM , DATE_FORMAT(OH.ENTDATE,'%Y-%m-%d') AS ENTDATE, IF(OH.ENTTIME IS NULL OR TRIM(OH.ENTTIME) = '', '', DATE_FORMAT(STR_TO_DATE(OH.ENTTIME,'%H%i%s'),'%H:%i:%s')) AS ENTTIME , DATE_FORMAT(OH.EXTDATE,'%Y-%m-%d') AS EXTDATE, IF(OH.EXTTIME IS NULL OR TRIM(OH.EXTTIME) = '', '', DATE_FORMAT(STR_TO_DATE(OH.EXTTIME,'%H%i%s'),'%H:%i:%s')) AS EXTTIME , DATE_FORMAT(OH.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(OH.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(OH.CREUSER) AS CREUSER , DATE_FORMAT(OH.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(OH.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(OH.LMOUSER) AS LMOUSER, OH.UPDTCHK FROM ${userData.schema}.OOUBHD OH LEFT JOIN ${userData.schema}.OOUBIT OOU ON OOU.OUTBOKY = OH.OUTBOKY LEFT JOIN ${userData.schema}.TPWPWG TWG ON OH.VHPLNKY = TWG.VHPLNKY INNER JOIN ${userData.schema}.TPLNHD TPH ON OH.VHPLNKY = TPH.VHPLNKY INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = OH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = OH.WAREKEY AND MD.DOCCATE = OH.DOCCATE AND MD.DOCTYPE = OH.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = OH.OBOSTAT AND MC.COMCDKY = 'OBOSTAT' AND MC.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = OH.WAREKEY AND MR.DOCCATE = OH.DOCCATE AND MR.DOCTYPE = OH.DOCTYPE AND MR.RSNCODE = OH.RSNCODE AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VOWNKEY = OH.VOWNKEY AND MV.VEHICKY = OH.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVOWMA MO ON MO.VOWNKEY = OH.VOWNKEY AND MO.VOUSEYN = 'Y' WHERE OH.WAREKEY = #{param.warekey}
AND OH.OBOSTAT IN
#{obostat}
AND OH.OBOSTAT = #{param.obostat}
AND UPPER(TRIM(OH.OUTBOKY)) LIKE CONCAT('%', UPPER(TRIM(#{param.outboky})),'%')
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND DATE_FORMAT(STR_TO_DATE(OOU.OUBRQDT, '%Y%m%d'), '%Y-%m-%d') >= #{param.oubrqdtFrom}
AND DATE_FORMAT(STR_TO_DATE(OOU.OUBRQDT, '%Y%m%d'), '%Y-%m-%d') <= #{param.oubrqdtTo}
AND UPPER(TRIM(OOU.DEMODNM)) LIKE CONCAT('%', UPPER(TRIM(#{param.demodnm})) ,'%')
AND UPPER(TRIM(OOU.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND (UPPER(TRIM(OOU.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%') OR (TRIM(#{param.skumkey}) = '' AND OOU.SKUMKEY IS NULL))
AND UPPER(TRIM(OOU.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND (UPPER(TRIM(OOU.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%') OR (TRIM(#{param.orderln}) = '' AND OOU.ORDERLN IS NULL))
AND DATE_FORMAT(STR_TO_DATE(OOU.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(OOU.SHPLIMT, '%Y%m%d'), '%Y-%m-%d')<= #{param.shplimtTo}
AND OH.ENTDOYN = #{param.entdoyn}
GROUP BY OH.OUTBOKY, OH.WAREKEY, MW.WHNAMLC , OH.VOWNKEY, MO.VONAMLC, OH.VEHICKY, MV.VHCFNAM , OH.DOCCATE, MD.DOCCTNM, OH.DOCTYPE, MD.DOCTYNM , OH.RSNCODE, MR.RSNCDNM, OH.PARSNNM, OH.SHPWEIG
, OH.VHPLNKY , OH.TPRILOC, OH.SPRILOC , OH.OBODATE, OH.OBOTIME , OH.OBOSTAT, MC.COMCDTX , OH.ENTDATE, OH.ENTTIME , OH.EXTDATE, OH.EXTTIME , OH.ENTDOYN , OH.CREDATE , OH.CRETIME , OH.CREUSER , OH.LMODATE , OH.LMOTIME , OH.LMOUSER, OH.UPDTCHK ORDER BY OH.OUTBOKY DESC

		/* getOoubitShlockyGroup */
		SELECT
            OOU.OUTBOKY, OOU.WAREKEY, OOU.SHLOCKY, OOU.EQUIPKY
        FROM
            ${userData.schema}.OOUBIT OOU
        WHERE
            OOU.WAREKEY = #{param.warekey}
            AND OOU.OUTBOKY = #{param.outboky}
        GROUP BY OOU.SHLOCKY, OOU.EQUIPKY

/* getDoe054HeadList */ SELECT OH.OUTBOKY, OH.WAREKEY, MW.WHNAMLC , OH.VOWNKEY, MO.VONAMLC, OH.VEHICKY, MV.VHCFNAM , OH.DOCCATE, MD.DOCCTNM, OH.DOCTYPE, MD.DOCTYNM , OH.RSNCODE, MR.RSNCDNM, OH.PARSNNM, WPL.SHPPLKY , OH.SHPWEIG , DATE_FORMAT(WPL.WPLDATE, '%Y-%m-%d') AS WPLNDAT, DATE_FORMAT(STR_TO_DATE(WPL.WPLTIME,'%H%i%s'),'%H:%i:%s') as WPLNTIM , DATE_FORMAT(OH.OBODATE,'%Y-%m-%d') as OBODATE, DATE_FORMAT(STR_TO_DATE(OH.OBOTIME,'%H%i%s'),'%H:%i:%s') as OBOTIME , OH.OBOSTAT, MC.COMCDTX as TSTSNAM , DATE_FORMAT(OH.ENTDATE,'%Y-%m-%d') AS ENTDATE, IF(OH.ENTTIME IS NULL OR TRIM(OH.ENTTIME) = '', '', DATE_FORMAT(STR_TO_DATE(OH.ENTTIME,'%H%i%s'),'%H:%i:%s')) AS ENTTIME , DATE_FORMAT(OH.EXTDATE,'%Y-%m-%d') AS EXTDATE, IF(OH.EXTTIME IS NULL OR TRIM(OH.EXTTIME) = '', '', DATE_FORMAT(STR_TO_DATE(OH.EXTTIME,'%H%i%s'),'%H:%i:%s')) AS EXTTIME , DATE_FORMAT( OH.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(OH.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(OH.CREUSER) , DATE_FORMAT(OH.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(OH.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(OH.LMOUSER), OH.UPDTCHK FROM ${userData.schema}.OOUBHD OH LEFT JOIN ${userData.schema}.OOUBIT OOU ON OOU.OUTBOKY = OH.OUTBOKY LEFT JOIN ${userData.schema}.WPLNHD WPL ON WPL.SHPPLKY = OOU.SHPPLKY INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = OH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = OH.WAREKEY AND MD.DOCCATE = OH.DOCCATE AND MD.DOCTYPE = OH.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = OH.OBOSTAT AND MC.COMCDKY = 'OBOSTAT' AND MC.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = OH.WAREKEY AND MR.DOCCATE = OH.DOCCATE AND MR.DOCTYPE = OH.DOCTYPE AND MR.RSNCODE = OH.RSNCODE AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VOWNKEY = OH.VOWNKEY AND MV.VEHICKY = OH.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVOWMA MO ON MO.VOWNKEY = OH.VOWNKEY AND MO.VOUSEYN = 'Y' WHERE OH.WAREKEY = #{param.warekey} AND OH.OBOSTAT != 'CANCEL'
AND OH.OBOSTAT = #{param.obostat}
AND UPPER(TRIM(OH.OUTBOKY)) LIKE CONCAT('%', UPPER(TRIM(#{param.outboky})),'%')
AND UPPER(TRIM(OOU.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND (UPPER(TRIM(OOU.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%') OR (TRIM(#{param.skumkey}) = '' AND OOU.SKUMKEY IS NULL))
AND UPPER(TRIM(OOU.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND (UPPER(TRIM(OOU.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%') OR (TRIM(#{param.orderln}) = '' AND OOU.ORDERLN IS NULL))
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND DATE_FORMAT(STR_TO_DATE(OOU.OUBRQDT, '%Y%m%d'), '%Y-%m-%d') >= #{param.oubrqdtFrom}
AND DATE_FORMAT(STR_TO_DATE(OOU.OUBRQDT, '%Y%m%d'), '%Y-%m-%d') <= #{param.oubrqdtTo}
GROUP BY OH.OUTBOKY, OH.WAREKEY, MW.WHNAMLC, OH.VOWNKEY , MO.VONAMLC, OH.VEHICKY, MV.VHCFNAM, OH.DOCCATE , MD.DOCCTNM, OH.DOCTYPE, MD.DOCTYNM, OH.RSNCODE , MR.RSNCDNM, OH.PARSNNM, OH.SHPWEIG, OH.OBOSTAT , MC.COMCDTX ORDER BY OH.OUTBOKY DESC

/* getDoe053ItemList */ SELECT
OH.OUTBOKY, OH.OUTBOIT,
OH.DOCCATE, OH.DOCTYPE, OH.WAREKEY, OH.POSHPDT, OH.POSHPTM, OH.POSHPDY, OH.OWNERKY, OH.OWNRNAM, OH.CUSTCOD, OH.CUSTNAM, OH.FNCUSKY, OH.REGIORG, OH.REGIMOD, OH.DESTORG, OH.DESTMOD, OH.DEORGNM, OH.DEMODNM, OH.DEMODYN, OH.DEMDMAN, OH.DEMDADR, OH.DEMPOCD, OH.DEMDTLN, OH.OBOMEMO, OH.OUBRQDT, OH.OUBRQTM, OH.SKUGRKY, OH.SKUMKEY, OH.SKUDESC, OH.SKUWEIG, OH.SKUWIDT, OH.SKULENG, OH.SKUTHIC, OH.GROSSWG, OH.GROSSWD, OH.GROSSLN, OH.GROSSTH, OH.FRAREKY, OH.FRLOCKY, OH.FRLAYER, OH.SHLOCKY, OH.RGITQTY , OH.SHCFQTY, OH.SUOMKEY, OH.SHPPLKY, OH.SHPPLIT, OH.VHPLNKY, OH.VHPLNIT, OH.PLNSIZE, OH.OBOITST, OH.ITEMCOD, OH.PURCNUM, OH.ORDERLN, OH.STLOTNB, DATE_FORMAT(OH.SHPLIMT, '%Y-%m-%d') AS SHPLIMT, DATE_FORMAT(OH.DELVDSR, '%Y-%m-%d') AS DELVDSR, OH.BTRFSTC, OH.PARSNCD, OH.PARSNNM, OH.EQUIPKY, OH.BTRFSTC, OH.ADDCOKY, OH.RCVDCDT, OH.RCVDCTM, OH.RCVDCKY, OH.RCVDCIT,
MW.WHNAMLC AS WHNAMLC, MR1.RENAMLC AS RGORGNM, MR2.RENAMLC AS RGMODNM, MA1.AREANAM AS FRARANM, MC.COMCDTX AS TSTSNAM, ML1.LOCANAM AS FRLOCNM, ML2.LOCANAM AS SHLONAM, MD3.COMCDTX AS ADDCNAM, BTC.BTRCNAM AS BTRCNAM, MGP.GRPKYNM AS GRPKYNM,
DATE_FORMAT(OH.CREDATE,'%Y-%m-%d') as CREDATE, DATE_FORMAT(STR_TO_DATE(OH.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME, ${userData.schema}.FN_SY_USERNAM(OH.CREUSER) AS CREUSER, DATE_FORMAT(OH.LMODATE,'%Y-%m-%d') as LMODATE, DATE_FORMAT(STR_TO_DATE(OH.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME, ${userData.schema}.FN_SY_USERNAM(OH.LMOUSER) AS LMOUSER, OH.UPDTCHK FROM ${userData.schema}.OOUBIT OH INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = OH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = OH.WAREKEY AND MA1.AREAKEY = OH.FRAREKY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = OH.WAREKEY AND ML1.AREAKEY = OH.FRAREKY AND ML1.LOCAKEY = OH.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = OH.WAREKEY AND ML2.AREAKEY = OH.FRAREKY AND ML2.LOCAKEY = OH.SHLOCKY AND ML2.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = OH.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = OH.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = OH.OBOITST AND MC.COMCDKY = 'OBOITST' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGP ON MGP.SKUGRKY = OH.SKUGRKY INNER JOIN ${userData.schema}.BTRCAT BTC ON BTC.BTRCATE = OH.BTRCATE LEFT JOIN ( SELECT MCJ.COMCDTX, BC.ADDCOKY FROM ${userData.schema}.MCODEM MCJ INNER JOIN ${userData.schema}.BADDCO BC ON BC.ADDSIKY = MCJ.COMCDVL ) AS MD3 ON MD3.ADDCOKY = OH.ADDCOKY LEFT JOIN ${userData.schema}.MCUSMA MCU1 ON MCU1.CUSTKEY = OH.OWNERKY AND MCU1.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MCU2 ON MCU2.CUSTKEY = OH.CUSTCOD AND MCU2.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MD1 ON MD1.REGIKEY = OH.REGIORG AND MD1.CUSTKEY = OH.OWNERKY AND MD1.DESTKEY = OH.DESTORG AND MD1.DEUSEYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MD2 ON MD2.REGIKEY = OH.REGIMOD AND MD2.CUSTKEY = OH.OWNERKY AND MD2.DESTKEY = OH.DESTMOD AND MD2.DEUSEYN = 'Y' WHERE OH.WAREKEY = #{param.warekey}
AND UPPER(TRIM(OH.OUTBOKY)) LIKE CONCAT('%', UPPER(TRIM(#{param.outboky})),'%')
AND OH.OBOITST = #{param.oboitst}
GROUP BY OH.OUTBOKY, OH.OUTBOIT, OH.WAREKEY, MW.WHNAMLC , OH.OWNERKY, OH.OWNRNAM, OH.CUSTCOD, OH.CUSTNAM , OH.REGIORG, MR1.RENAMLC, OH.DESTORG , OH.DEORGNM, OH.REGIMOD, MR2.RENAMLC , OH.DESTMOD, OH.DEMODNM, OH.OBOMEMO, OH.OUBRQDT , OH.OUBRQTM, OH.SKUGRKY, OH.SKUMKEY, OH.SKUDESC , OH.SKUWEIG, OH.SKUWIDT, OH.SKULENG, OH.SKUTHIC , OH.GROSSWG, OH.GROSSWD, OH.GROSSLN, OH.GROSSTH , OH.FRAREKY, MA1.AREANAM, OH.FRLOCKY , ML1.LOCANAM, OH.FRLAYER, OH.SHLOCKY , ML2.LOCANAM, OH.RGITQTY, OH.SHCFQTY , MGP.GRPKYNM , OH.SUOMKEY, OH.SHPPLKY, OH.SHPPLIT, OH.VHPLNKY , OH.VHPLNIT, OH.OBOITST, MC.COMCDTX , OH.ITEMCOD, OH.PURCNUM, OH.ORDERLN, OH.STLOTNB , OH.SHPLIMT, OH.DELVDSR, OH.BTRFSTC, OH.PARSNCD, OH.PARSNNM , OH.EQUIPKY, OH.BTRFSTC, OH.ADDCOKY , OH.RCVDCDT, OH.RCVDCTM, OH.RCVDCKY, OH.RCVDCIT , OH.CRETIME , OH.CREUSER , OH.LMODATE , OH.LMOTIME , OH.LMOUSER ORDER BY OH.WAREKEY, OH.FRAREKY, OH.FRLOCKY, OH.FRLAYER DESC

/* getDoe056HeadList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, COUNT(WT.TASKOIT) as TSITCNT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WTA.TASKSTS, MC.COMCDTX as TSTSNAM , OOU.VEHICKY, MV.VHCFNAM, WT.EQUIPKY, MEQ.EQUINAM, MEQ.AREAKEY, MA.AREANAM , WT.SHPDCKY , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MEQUMA MEQ ON MEQ.WAREKEY = WT.WAREKEY AND MEQ.AREAKEY = WT.TOAREKY AND MEQ.EQUIPKY = WT.EQUIPKY INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = MEQ.WAREKEY AND MA.AREAKEY = MEQ.AREAKEY LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.OOUBHD OOU ON OOU.OUTBOKY = WT.OUTBOKY INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VOWNKEY = OOU.VOWNKEY AND MV.VEHICKY = OOU.VEHICKY INNER JOIN ( SELECT TASKOKY, MIN(TASKSTS) as TASKSTS FROM ${userData.schema}.WTAKIT WHERE WAREKEY = #{param.warekey} GROUP BY TASKOKY ) as WTA ON WT.TASKOKY = WTA.TASKOKY INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WTA.TASKSTS AND MC.COMCDKY = 'TASKSTS' AND MC.COUSEYN = 'Y' WHERE WT.WAREKEY = #{param.warekey}
AND WT.DOCCATE = #{param.doccate}
AND WT.TASKSTS IN
#{tasksts}
AND UPPER(TRIM(WT.EQUIPKY)) = UPPER(TRIM(#{param.equipky}))
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})),'%')
AND UPPER(TRIM(WT.SKUMKEY)) = UPPER(TRIM(#{param.skumkey}))
AND UPPER(TRIM(WT.TASKOKY)) LIKE CONCAT('%', UPPER(TRIM(#{param.taskoky})),'%')
GROUP BY WT.TASKOKY, WT.WAREKEY, MW.WHNAMLC, WT.DOCCATE , MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM, WTA.TASKSTS, WT.EQUIPKY, MEQ.EQUINAM, MEQ.AREAKEY, MA.AREANAM ORDER BY WT.TASKOKY DESC

/* getDoe056WtakitList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, MC.COMCDTX as TSTSNAM, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, MA1.AREANAM as FRARANM, WT.FRLOCKY, ML1.LOCANAM as FRLOCNM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM as TOARANM, WT.TOLOCKY, ML2.LOCANAM as TOLOCNM , WT.EQUIPKY, WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WT.TASKSTS AND MC.COMCDKY = 'TASKSTS' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = WT.WAREKEY AND MA1.AREAKEY = WT.FRAREKY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA2 ON MA2.WAREKEY = WT.WAREKEY AND MA2.AREAKEY = WT.TOAREKY AND MA2.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WT.WAREKEY AND ML1.AREAKEY = WT.FRAREKY AND ML1.LOCAKEY = WT.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WT.WAREKEY AND ML2.AREAKEY = WT.TOAREKY AND ML2.LOCAKEY = WT.TOLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.OOUBIT OO ON OO.OUTBOKY = WT.OUTBOKY AND OO.OUTBOIT = WT.OUTBOIT WHERE WT.WAREKEY = #{param.warekey} AND OO.OBOITST = #{param.oboitst}
AND UPPER(TRIM(WT.SKUMKEY)) = UPPER(TRIM(#{param.skumkey}))
AND WT.TASKOKY = #{param.taskoky}
AND UPPER(TRIM(WS.CUSTKEY)) IN
UPPER(TRIM(#{custkey}))
AND UPPER(TRIM(WS.REGIKEY)) IN
UPPER(TRIM(#{regikey}))
GROUP BY WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , WT.TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, MC.COMCDTX, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, MA1.AREANAM, WT.FRLOCKY, ML1.LOCANAM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM, WT.TOLOCKY, ML2.LOCANAM, WT.TOLAYER , WT.EQUIPKY, WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , WT.CREDATE , WT.CRETIME , WT.CREUSER , WT.LMODATE , WT.LMOTIME , WT.LMOUSER , WT.UPDTCHK

mapper.delete:
/* deleteDoe056Stock */
DELETE
	FROM ${userData.schema}.WSTKKY
WHERE
	WAREKEY = #{param.warekey}
	AND STOCKKY = #{param.stockky}

mapper.select:
/* getDoe056WtakitShpdckyAnditList */
SELECT
    WAREKEY, SHPDCKY, SHPDCIT
FROM
    ${userData.schema}.WTAKIT
WHERE
    WAREKEY = #{param.warekey}
    AND TASKOKY = #{param.taskoky}

/* getDoe056WshpitStatList */ SELECT SHPDCKY, SHPDCIT, DOCCATE, DOCTYPE , WAREKEY, POSHPDT, POSHPTM, POSHPDY , SHPITST, OUTBOKY, OUTBOIT, OUBRQDT , OUBRQTM, SPEIDAT, SPEITIM, BTRCATE , OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM , FNCUSKY, SKUGRKY, SKUMKEY, SKUDESC , SKUTHIC, SKUWIDT, SKULENG, SKUWEIG , GROSSWD, GROSSLN, GROSSWG, GROSSTH , FRAREKY, FRLOCKY, FRLAYER, SHLOCKY , REGIORG, REGIMOD, DESTORG, DEORGNM , DESTMOD, DEMODNM, DEMODYN, DEMDMAN , DEMDADR, DEMPOCD, DEMDTLN, STLOTNB , PURCNUM, ORDERLN, ITEMCOD, SHPLIMT , DELVDSR, BTRFSTC, OBOMEMO, ALLGRKY , RGITQTY, SHALQTY, SHCFQTY, SUOMKEY , ADDCOKY , CREDATE, CRETIME, CREUSER, LMODATE , LMOTIME, LMOUSER, UPDTCHK FROM ${userData.schema}.WSHPIT WHERE WAREKEY = #{param.warekey} AND SHPDCKY = #{param.shpdcky}
AND SHPITST = #{param.shpitst}
GROUP BY SHPDCKY, SHPDCIT, DOCCATE, DOCTYPE , WAREKEY, POSHPDT, POSHPTM, POSHPDY , SHPITST, OUTBOKY, OUTBOIT, OUBRQDT , OUBRQTM, SPEIDAT, SPEITIM, BTRCATE , OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM , FNCUSKY, SKUGRKY, SKUMKEY, SKUDESC , SKUTHIC, SKUWIDT, SKULENG, SKUWEIG , GROSSWD, GROSSLN, GROSSWG, GROSSTH , FRAREKY, FRLOCKY, FRLAYER, SHLOCKY , REGIORG, REGIMOD, DESTORG, DEORGNM , DESTMOD, DEMODNM, DEMODYN, DEMDMAN , DEMDADR, DEMPOCD, DEMDTLN, STLOTNB , PURCNUM, ORDERLN, ITEMCOD, SHPLIMT , DELVDSR, BTRFSTC, OBOMEMO, ALLGRKY , RGITQTY, SHALQTY, SHCFQTY, SUOMKEY , ADDCOKY , CREDATE, CRETIME, CREUSER, LMODATE , LMOTIME, LMOUSER, UPDTCHK

/* getDoe057HeadList */ SELECT WS.SHPDCKY, WT.OUTBOKY , TPW.SHPPLKY , TPW.VHPLNKY , WS.WAREKEY, MW.WHNAMLC , WS.DOCCATE, MD.DOCCTNM, WS.DOCTYPE, MD.DOCTYNM , CASE WHEN ( SELECT EXISTS( SELECT A.TASKSTS FROM ${userData.schema}.WTAKIT A WHERE A.WAREKEY = WS.WAREKEY AND A.SHPDCKY = WS.SHPDCKY AND A.OUTBOKY = WT.OUTBOKY AND A.TASKSTS IN ('OPERSTR', 'TASKCMP') GROUP BY A.TASKSTS ) >= 1 ) THEN 'OPERSTR' ELSE CASE WHEN ( (SELECT EXISTS( SELECT A.TASKSTS FROM ${userData.schema}.WTAKIT A WHERE A.WAREKEY = WS.WAREKEY AND A.SHPDCKY = WS.SHPDCKY AND A.OUTBOKY = WT.OUTBOKY AND A.TASKSTS = 'SHPOUT' GROUP BY A.TASKSTS ) >= 1) AND (SELECT EXISTS( SELECT B.TASKSTS FROM ${userData.schema}.WTAKIT B WHERE B.WAREKEY = WS.WAREKEY AND B.SHPDCKY = WS.SHPDCKY AND B.OUTBOKY = WT.OUTBOKY AND B.TASKSTS = 'NEW' GROUP BY B.TASKSTS ) >= 1) ) THEN 'OPERSTR' ELSE CASE WHEN ( SELECT EXISTS( SELECT A.TASKSTS FROM ${userData.schema}.WTAKIT A WHERE A.WAREKEY = WS.WAREKEY AND A.SHPDCKY = WS.SHPDCKY AND A.OUTBOKY = WT.OUTBOKY AND A.TASKSTS = 'NEW' GROUP BY A.TASKSTS ) = 0 ) THEN 'OPERCMP' ELSE 'NEW' END END END AS TASKSTS1 , WS.VOWNKEY, MO.VONAMLC, WS.VEHICKY, MV.VHCFNAM, MV.DRVERNM , WS.SHPDCST, WS.PARSNCD, MR.RSNCDNM, WS.PARSNNM, WS.SHPWEIG , DATE_FORMAT(WS.WPLNDAT,'%Y-%m-%d') as WPLNDAT , DATE_FORMAT(STR_TO_DATE(WS.WPLNTIM,'%H%i%s'),'%H:%i:%s') as WPLNTIM , DATE_FORMAT(WS.OBODATE,'%Y-%m-%d') as OBODATE , DATE_FORMAT(STR_TO_DATE(WS.OBOTIME,'%H%i%s'),'%H:%i:%s') as OBOTIME , DATE_FORMAT(WS.SHPSDAY,'%Y-%m-%d') as SHPSDAY , DATE_FORMAT(STR_TO_DATE(WS.SHPSTIM,'%H%i%s'),'%H:%i:%s') as SHPSTIM , DATE_FORMAT(WS.SPEHDAT,'%Y-%m-%d') as SPEHDAT , DATE_FORMAT(STR_TO_DATE(WS.SPEHTIM,'%H%i%s'),'%H:%i:%s') as SPEHTIM , MC1.COMCDTX AS SHPSTNM , ( SELECT A.COMCDTX FROM ${userData.schema}.MCODEM A WHERE A.COMCDKY = 'TASKSTS' AND A.COMCDVL = TASKSTS1 AND A.COUSEYN = 'Y' ) AS TSKSTNM , IF(( SELECT COUNT(A.VHPLNKY) FROM ${userData.schema}.TPLNHD A WHERE A.WAREKEY = WT.WAREKEY AND A.TPNSTAT IN ('START', 'REFUSAL', 'FINISH') AND (A.VHPLNKY) IN ( SELECT B.VHPLNKY FROM ${userData.schema}.OOUBIT B WHERE B.WAREKEY = WT.WAREKEY AND B.OUTBOKY = WT.OUTBOKY ) ) >= 1, 'Y', 'N') AS TRANSYN FROM ${userData.schema}.WSHPHD WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WS.WAREKEY AND MD.DOCCATE = WS.DOCCATE AND MD.DOCTYPE = WS.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC1 ON MC1.COMCDVL = WS.SHPDCST AND MC1.COMCDKY = 'SHPDCST' AND MC1.COUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VOWNKEY = WS.VOWNKEY AND MV.VEHICKY = WS.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVOWMA MO ON MO.VOWNKEY = WS.VOWNKEY AND MO.VOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WS.WAREKEY AND MR.DOCCATE = WS.DOCCATE AND MR.DOCTYPE = WS.DOCTYPE AND MR.RSNCODE = WS.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.WTAKIT WT ON WT.WAREKEY = WS.WAREKEY AND WT.SHPDCKY = WS.SHPDCKY INNER JOIN ${userData.schema}.OOUBIT OOU ON OOU.OUTBOKY = WT.OUTBOKY AND OOU.OUTBOIT = WT.OUTBOIT INNER JOIN ${userData.schema}.TPWPWG TPW ON TPW.VHPLNKY = OOU.VHPLNKY AND TPW.SHPPLKY = OOU.SHPPLKY AND TPW.PLNSIZE = OOU.PLNSIZE INNER JOIN ${userData.schema}.WSHPIT WSI ON WSI.SHPDCKY = WS.SHPDCKY WHERE WS.WAREKEY = #{param.warekey}
AND WS.SHPDCST = #{param.shpdcst}
AND WS.SHPDCST IN
#{item}
AND UPPER(TRIM(WT.TASKSTS)) LIKE CONCAT('%', UPPER(TRIM(#{param.tasksts})), '%')
AND UPPER(TRIM(WS.SHPDCKY)) LIKE CONCAT('%', UPPER(TRIM(#{param.shpdcky})), '%')
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND DATE_FORMAT(STR_TO_DATE(WS.SHPSDAY, '%Y%m%d'), '%Y-%m-%d') >= #{param.shpsdayFrom}
AND DATE_FORMAT(STR_TO_DATE(WS.SHPSDAY, '%Y%m%d'), '%Y-%m-%d') <= #{param.shpsdayTo}
AND UPPER(TRIM(WSI.DEMODNM)) LIKE CONCAT('%', UPPER(TRIM(#{param.demodnm})),'%')
AND UPPER(TRIM(WSI.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND UPPER(TRIM(WSI.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND UPPER(TRIM(WSI.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND UPPER(TRIM(WSI.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND DATE_FORMAT(STR_TO_DATE(WSI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WSI.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
GROUP BY WS.SHPDCKY, WT.OUTBOKY , TPW.VHPLNKY , WS.WAREKEY, MW.WHNAMLC , WS.DOCCATE, MD.DOCCTNM, WS.DOCTYPE, MD.DOCTYNM , WS.VOWNKEY, MO.VONAMLC, WS.VEHICKY, MV.VHCFNAM, MV.DRVERNM , WS.SHPDCST, WS.PARSNCD, MR.RSNCDNM, WS.PARSNNM, WS.SHPWEIG , WS.WPLNDAT , WS.WPLNTIM , WS.OBODATE , WS.OBOTIME , WS.SHPSDAY , WS.SHPSTIM , WS.SPEHDAT , WS.SPEHTIM , MC1.COMCDTX ORDER BY WS.SHPDCKY DESC, WT.OUTBOKY DESC, TPW.SHPPLKY DESC, TPW.VHPLNKY DESC

/* getDoe057ItemList */ SELECT CONCAT(WS.SHPDCKY, WS.SHPDCIT) AS ROWKEY , WS.SHPDCKY, WS.SHPDCIT, WS.DOCCATE, WS.DOCTYPE, WS.WAREKEY , DATE_FORMAT(WS.POSHPDT, '%Y-%m-%d') AS POSHPDT , DATE_FORMAT(STR_TO_DATE(WS.POSHPTM,'%H%i%s'),'%H:%i:%s') AS POSHPTM , WS.POSHPDY, WS.SHPITST, WS.OUTBOKY, WS.OUTBOIT , DATE_FORMAT(WS.OUBRQDT,'%Y-%m-%d') AS OUBRQDT , IF(WS.OUBRQTM IS NULL OR TRIM(WS.OUBRQTM) = '', '', DATE_FORMAT(STR_TO_DATE(WS.OUBRQTM,'%H%i%s'),'%H:%i:%s')) AS OUBRQTM , DATE_FORMAT(WS.SPEIDAT,'%Y-%m-%d') AS SPEIDAT , IF(WS.SPEITIM IS NULL OR TRIM(WS.SPEITIM) = '', '', DATE_FORMAT(STR_TO_DATE(WS.SPEITIM,'%H%i%s'),'%H:%i:%s')) AS SPEITIM , WS.BTRCATE, WS.OWNERKY, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY , WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUTHIC, WS.SKUWIDT , WS.SKULENG, WS.SKUWEIG, WS.GROSSWD, WS.GROSSLN, WS.GROSSWG , WS.GROSSTH, WS.FRAREKY, WS.FRLOCKY, WS.FRLAYER, WS.SHLOCKY , WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DESTMOD, WS.DEMODYN , WS.DEMDMAN, WS.DEMDADR, WS.DEMPOCD, WS.DEMDTLN , WS.STLOTNB , WS.PURCNUM, WS.ORDERLN, WS.ITEMCOD, WS.EMSKUYN , DATE_FORMAT(WS.SHPLIMT, '%Y-%m-%d') AS SHPLIMT , DATE_FORMAT(WS.DELVDSR, '%Y-%m-%d') AS DELVDSR , WS.BTRFSTC, WS.OBOMEMO , WS.ALLGRKY, WS.RGITQTY, WS.SHALQTY , WS.SHCFQTY, WS.ADDCOKY
, MW.WHNAMLC AS WHNAMLC, MC01.COMCDTX AS TSTSNAM, MA.AREANAM AS FRARENM , ML1.LOCANAM AS FRLOCNM, ML2.LOCANAM as SHLCNAM , MR1.RENAMLC AS RGORGNM, MR2.RENAMLC AS RGMODNM , IF((WS.DESTORG IS NULL OR TRIM(WS.DESTORG) = ''), WS.DEORGNM, MD1.DENAMLC) AS DEORGNM , IF((WS.DESTMOD IS NULL OR TRIM(WS.DESTMOD) = ''), WS.DEMODNM, MD2.DENAMLC) AS DEMODNM , IF((WS.OWNERKY IS NULL OR TRIM(WS.OWNERKY) = ''), WS.OWNRNAM, MC1.CUNAMLC) AS OWNRNAM , IF((WS.CUSTCOD IS NULL OR TRIM(WS.CUSTCOD) = ''), WS.CUSTNAM, MC2.CUNAMLC) AS CUSTNAM , WTI.TASKOKY, WTI.TASKOIT, WTI.TASKSTS, MC02.COMCDTX AS TSKSTNM , MG.GRPKYNM AS GRPKYNM, BT.BTRCNAM AS BTRCNAM, WTI.EQUIPKY , WS.RCVDCDT, WS.RCVDCTM, WS.RCVDCKY, WS.RCVDCIT , BT.BTRCNAM, MCD4.COMCDTX AS ADDCNAM
, DATE_FORMAT(STR_TO_DATE(WS.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WS.CREUSER) AS CREUSER , DATE_FORMAT(WS.LMODATE, '%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(WS.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER, WS.UPDTCHK FROM ${userData.schema}.WSHPIT WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.FRAREKY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WS.WAREKEY AND ML1.AREAKEY = WS.FRAREKY AND ML1.LOCAKEY = WS.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC01 ON MC01.COMCDKY = 'SHPITST' AND MC01.COMCDVL = WS.SHPITST AND MC01.COUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = WS.BTRCATE INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WS.SKUGRKY AND MG.GRUSEYN = 'Y' LEFT JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WS.WAREKEY AND ML2.AREAKEY = WS.FRAREKY AND ML2.LOCAKEY = WS.SHLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.WTAKIT WTI ON WTI.WAREKEY = WS.WAREKEY AND WTI.SHPDCKY= WS.SHPDCKY AND WTI.SHPDCIT = WS.SHPDCIT LEFT JOIN ${userData.schema}.MCODEM MC02 ON MC02.COMCDKY = 'TASKSTS' AND MC02.COMCDVL = WTI.TASKSTS AND MC02.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MD1 ON MD1.CUSTKEY = WS.OWNERKY AND MD1.REGIKEY = WS.REGIORG AND MD1.DESTKEY = WS.DESTORG AND MD1.DEUSEYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MD2 ON MD2.CUSTKEY = WS.OWNERKY AND MD2.REGIKEY = WS.REGIMOD AND MD2.DESTKEY = WS.DESTMOD AND MD2.DEUSEYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MC1 ON MC1.CUSTKEY = WS.OWNERKY AND MC1.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MC2 ON MC2.CUSTKEY = WS.CUSTCOD AND MC2.CUDELYN = 'Y' LEFT JOIN ( SELECT MC.COMCDTX, BC.ADDCOKY FROM ${userData.schema}.MCODEM MC INNER JOIN ${userData.schema}.BADDCO BC ON BC.ADDSIKY = MC.COMCDVL ) AS MCD4 ON MCD4.ADDCOKY = WS.ADDCOKY WHERE WS.WAREKEY = #{param.warekey}
AND (WS.SHPDCKY = #{param.shpdcky})
AND (OOU.OUTBOKY = #{param.outboky} OR OOU.OUTBOKY IS NULL)
GROUP BY WS.SHPDCKY, WS.SHPDCIT, WS.DOCCATE, WS.DOCTYPE, WS.WAREKEY , WS.POSHPDT, WS.POSHPTM, WS.POSHPDY, WS.SHPITST, WS.OUTBOKY , WS.OUTBOIT, WS.OUBRQDT, WS.OUBRQTM, WS.SPEIDAT, WS.SPEITIM , WS.BTRCATE, WS.OWNERKY, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY , WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUTHIC, WS.SKUWIDT , WS.SKULENG, WS.SKUWEIG, WS.GROSSWD, WS.GROSSLN, WS.GROSSWG , WS.GROSSTH, WS.FRAREKY, WS.FRLOCKY, WS.FRLAYER, WS.SHLOCKY , WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DESTMOD, WS.DEMODYN , WS.DEMDMAN, WS.DEMDADR, WS.DEMPOCD, WS.DEMDTLN , WS.STLOTNB , WS.PURCNUM, WS.ORDERLN , WS.ITEMCOD, WS.SHPLIMT, WS.DELVDSR , WS.BTRFSTC, WS.OBOMEMO , WS.ALLGRKY, WS.RGITQTY, WS.SHALQTY , WS.SHCFQTY, MW.WHNAMLC, MC01.COMCDTX, MA.AREANAM, ML1.LOCANAM , ML2.LOCANAM, MR1.RENAMLC, MR2.RENAMLC, WS.DEORGNM, WS.DEMODNM , WS.OWNRNAM, WS.CUSTNAM, WTI.TASKOKY, WTI.TASKOIT, WTI.TASKSTS , MC02.COMCDTX, MG.GRPKYNM, BT.BTRCNAM , WS.RCVDCDT , WS.RCVDCTM, WS.RCVDCKY, WS.RCVDCIT , WS.ADDCOKY, WS.EMSKUYN, WTI.EQUIPKY , WS.CRETIME, WS.CREUSER, WS.LMODATE, WS.LMOTIME, WS.LMOUSER , WS.UPDTCHK

/* getDoe057TotalList */ SELECT CONCAT(WS.SHPDCKY, WS.SHPDCIT) AS ROWKEY , WS.SHPDCKY, WS.SHPDCIT, WS.DOCCATE, WS.DOCTYPE, WS.WAREKEY , DATE_FORMAT(WS.POSHPDT, '%Y-%m-%d') AS POSHPDT , DATE_FORMAT(STR_TO_DATE(WS.POSHPTM,'%H%i%s'),'%H:%i:%s') AS POSHPTM , WS.POSHPDY, WS.SHPITST, WS.OUTBOKY, WS.OUTBOIT , DATE_FORMAT(WS.OUBRQDT,'%Y-%m-%d') AS OUBRQDT , IF(WS.OUBRQTM IS NULL OR TRIM(WS.OUBRQTM) = '', '', DATE_FORMAT(STR_TO_DATE(WS.OUBRQTM,'%H%i%s'),'%H:%i:%s')) AS OUBRQTM , DATE_FORMAT(WS.SPEIDAT,'%Y-%m-%d') AS SPEIDAT , IF(WS.SPEITIM IS NULL OR TRIM(WS.SPEITIM) = '', '', DATE_FORMAT(STR_TO_DATE(WS.SPEITIM,'%H%i%s'),'%H:%i:%s')) AS SPEITIM , WS.BTRCATE, WS.OWNERKY, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY , WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUTHIC, WS.SKUWIDT , WS.SKULENG, WS.SKUWEIG, WS.GROSSWD, WS.GROSSLN, WS.GROSSWG , WS.GROSSTH, WS.FRAREKY, WS.FRLOCKY, WS.FRLAYER, WS.SHLOCKY , WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DESTMOD, WS.DEMODYN , WS.DEMDMAN, WS.DEMDADR, WS.DEMPOCD, WS.DEMDTLN , WS.STLOTNB , WS.PURCNUM, WS.ORDERLN, WS.ITEMCOD, WS.EMSKUYN , DATE_FORMAT(WS.SHPLIMT, '%Y-%m-%d') AS SHPLIMT , DATE_FORMAT(WS.DELVDSR, '%Y-%m-%d') AS DELVDSR , WS.BTRFSTC, WS.OBOMEMO , WS.ALLGRKY, WS.RGITQTY, WS.SHALQTY , WS.SHCFQTY, WS.ADDCOKY
, MW.WHNAMLC AS WHNAMLC, MC01.COMCDTX AS TSTSNAM, MA.AREANAM AS FRARENM , ML1.LOCANAM AS FRLOCNM, ML2.LOCANAM as SHLCNAM , MR1.RENAMLC AS RGORGNM, MR2.RENAMLC AS RGMODNM , IF((WS.DESTORG IS NULL OR TRIM(WS.DESTORG) = ''), WS.DEORGNM, MD1.DENAMLC) AS DEORGNM , IF((WS.DESTMOD IS NULL OR TRIM(WS.DESTMOD) = ''), WS.DEMODNM, MD2.DENAMLC) AS DEMODNM , IF((WS.OWNERKY IS NULL OR TRIM(WS.OWNERKY) = ''), WS.OWNRNAM, MC1.CUNAMLC) AS OWNRNAM , IF((WS.CUSTCOD IS NULL OR TRIM(WS.CUSTCOD) = ''), WS.CUSTNAM, MC2.CUNAMLC) AS CUSTNAM , WTI.TASKOKY, WTI.TASKOIT, WTI.TASKSTS, MC02.COMCDTX AS TSKSTNM , MG.GRPKYNM AS GRPKYNM, BT.BTRCNAM AS BTRCNAM, WTI.EQUIPKY , WS.RCVDCDT, WS.RCVDCTM, WS.RCVDCKY, WS.RCVDCIT , BT.BTRCNAM, MCD4.COMCDTX AS ADDCNAM , MV.VHCFNAM, MV.DRVERNM, WSH.SHPDCST , DATE_FORMAT(WSH.SHPSDAY, '%Y-%m-%d') AS SHPSDAY , DATE_FORMAT(STR_TO_DATE(WSH.SHPSTIM, '%H%i%s'), '%H:%i:%s') AS SHPSTIM , DATE_FORMAT(WSH.SPEHDAT, '%Y-%m-%d') AS SPEHDAT , DATE_FORMAT(STR_TO_DATE(WSH.SPEHTIM, '%H%i%s'), '%H:%i:%s') AS SPEHTIM
, DATE_FORMAT(WS.CREDATE, '%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(WS.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WS.CREUSER) AS CREUSER , DATE_FORMAT(WS.LMODATE, '%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(WS.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER, WS.UPDTCHK FROM ${userData.schema}.WSHPIT WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.FRAREKY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WS.WAREKEY AND ML1.AREAKEY = WS.FRAREKY AND ML1.LOCAKEY = WS.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC01 ON MC01.COMCDKY = 'SHPITST' AND MC01.COMCDVL = WS.SHPITST AND MC01.COUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = WS.BTRCATE INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = WS.SKUGRKY AND MG.GRUSEYN = 'Y' INNER JOIN ${userData.schema}.WSHPHD WSH ON WS.SHPDCKY = WSH.SHPDCKY AND WS.WAREKEY = WSH.WAREKEY INNER JOIN ${userData.commonSchema}.MVHCMA MV ON WSH.VOWNKEY = MV.VOWNKEY AND MV.VEHICKY = WSH.VEHICKY AND MV.VHUSEYN = 'Y' LEFT JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WS.WAREKEY AND ML2.AREAKEY = WS.FRAREKY AND ML2.LOCAKEY = WS.SHLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.WTAKIT WTI ON WTI.WAREKEY = WS.WAREKEY AND WTI.SHPDCKY= WS.SHPDCKY AND WTI.SHPDCIT = WS.SHPDCIT LEFT JOIN ${userData.schema}.MCODEM MC02 ON MC02.COMCDKY = 'TASKSTS' AND MC02.COMCDVL = WTI.TASKSTS AND MC02.COUSEYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MD1 ON MD1.CUSTKEY = WS.OWNERKY AND MD1.REGIKEY = WS.REGIORG AND MD1.DESTKEY = WS.DESTORG AND MD1.DEUSEYN = 'Y' LEFT JOIN ${userData.schema}.MDESMA MD2 ON MD2.CUSTKEY = WS.OWNERKY AND MD2.REGIKEY = WS.REGIMOD AND MD2.DESTKEY = WS.DESTMOD AND MD2.DEUSEYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MC1 ON MC1.CUSTKEY = WS.OWNERKY AND MC1.CUDELYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MC2 ON MC2.CUSTKEY = WS.CUSTCOD AND MC2.CUDELYN = 'Y' LEFT JOIN ( SELECT MC.COMCDTX, BC.ADDCOKY FROM ${userData.schema}.MCODEM MC INNER JOIN ${userData.schema}.BADDCO BC ON BC.ADDSIKY = MC.COMCDVL ) AS MCD4 ON MCD4.ADDCOKY = WS.ADDCOKY WHERE WS.WAREKEY = #{param.warekey}
AND (WS.SHPDCKY = #{param.shpdcky})
AND WSH.SHPDCST = #{param.shpdcst}
AND WSH.SHPDCST IN
#{item}
AND UPPER(TRIM(MV.VHCFNAM)) LIKE CONCAT('%', UPPER(TRIM(#{param.vhcfnam})), '%')
AND DATE_FORMAT(STR_TO_DATE(WSH.SHPSDAY, '%Y%m%d'), '%Y-%m-%d') >= #{param.shpsdayFrom}
AND DATE_FORMAT(STR_TO_DATE(WSH.SHPSDAY, '%Y%m%d'), '%Y-%m-%d') <= #{param.shpsdayTo}
AND UPPER(TRIM(WS.DEMODNM)) LIKE CONCAT('%', UPPER(TRIM(#{param.demodnm})),'%')
AND UPPER(TRIM(WS.SKUMKEY)) IN
UPPER(TRIM(#{skumkey}))
AND UPPER(TRIM(WS.SKUMKEY)) LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND UPPER(TRIM(WS.ORDERLN)) IN
UPPER(TRIM(#{orderln}))
AND UPPER(TRIM(WS.ORDERLN)) LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND DATE_FORMAT(STR_TO_DATE(WS.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') >= #{param.shplimtFrom}
AND DATE_FORMAT(STR_TO_DATE(WS.SHPLIMT, '%Y%m%d'), '%Y-%m-%d') <= #{param.shplimtTo}
GROUP BY WS.SHPDCKY, WS.SHPDCIT, WS.DOCCATE, WS.DOCTYPE, WS.WAREKEY , WS.POSHPDT, WS.POSHPTM, WS.POSHPDY, WS.SHPITST, WS.OUTBOKY , WS.OUTBOIT, WS.OUBRQDT, WS.OUBRQTM, WS.SPEIDAT, WS.SPEITIM , WS.BTRCATE, WS.OWNERKY, WS.CUSTCOD, WS.CUSTNAM, WS.FNCUSKY , WS.SKUGRKY, WS.SKUMKEY, WS.SKUDESC, WS.SKUTHIC, WS.SKUWIDT , WS.SKULENG, WS.SKUWEIG, WS.GROSSWD, WS.GROSSLN, WS.GROSSWG , WS.GROSSTH, WS.FRAREKY, WS.FRLOCKY, WS.FRLAYER, WS.SHLOCKY , WS.REGIORG, WS.REGIMOD, WS.DESTORG, WS.DESTMOD, WS.DEMODYN , WS.DEMDMAN, WS.DEMDADR, WS.DEMPOCD, WS.DEMDTLN , WS.STLOTNB , WS.PURCNUM, WS.ORDERLN , WS.ITEMCOD, WS.SHPLIMT, WS.DELVDSR , WS.BTRFSTC, WS.OBOMEMO , WS.ALLGRKY, WS.RGITQTY, WS.SHALQTY , WS.SHCFQTY, MW.WHNAMLC, MC01.COMCDTX, MA.AREANAM, ML1.LOCANAM , ML2.LOCANAM, MR1.RENAMLC, MR2.RENAMLC, WS.DEORGNM, WS.DEMODNM , WS.OWNRNAM, WS.CUSTNAM, WTI.TASKOKY, WTI.TASKOIT, WTI.TASKSTS , MC02.COMCDTX, MG.GRPKYNM, BT.BTRCNAM , WS.RCVDCDT, WS.RCVDCTM, WS.RCVDCKY, WS.RCVDCIT , WS.ADDCOKY, WS.EMSKUYN, WTI.EQUIPKY , WSH.SHPDCST, WSH.SHPSDAY, WSH.SHPSTIM, MV.VHCFNAM , MV.DRVERNM, WSH.SPEHDAT, WSH.SPEHTIM , WS.CRETIME, WS.CREUSER, WS.LMODATE, WS.LMOTIME, WS.LMOUSER , WS.UPDTCHK ORDER BY SHPSDAY DESC

mapper.update:
/* updateShpitstCMP */
UPDATE ${userData.schema}.WSHPIT
	SET SHPITST = #{param.shpitst},
		SHCFQTY = 1,
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = UPDTCHK + 1
	WHERE
		WAREKEY = #{param.warekey}
		AND SHPDCKY = #{param.shpdcky}

			AND SHPDCIT = #{param.shpdcit}

		AND SHPITST != 'CANCEL'

mapper.delete:
/* deleteWshpitForChangeInvoice */
DELETE
FROM
	${userData.schema}.WSHPIT
WHERE
	WAREKEY = #{param.warekey}
	AND SHPDCKY = #{param.shpdcky}
	AND SHPDCIT = #{param.shpdcit}
	AND SKUMKEY = #{param.skumkey}
	AND UPDTCHK = #{param.updtchk}

mapper.select:
/* selectStockForShipPlan */ SELECT
STOCKKY,
WAREKEY, AREAKEY, LOCAKEY, LOLAYER, SAVEPNT, LOTNMKY, OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM, FNCUSKY, FCNAMLC, SKUGRKY, SKUMKEY, SKUDESC, SKUWEIG, SKUWIDT, SKULENG, SKUTHIC, STLOTNB, GROSSWG, GROSSLN, GROSSWD, GROSSTH, BTRCATE, BTRFSTC, PURCNUM, ORDERLN, REGIKEY, DESTKEY, REGIORG, REGIMOD, DESTORG, DEORGNM, DESTMOD, ITEMCOD, DEMODNM, DEMODYN, DEMDMAN, DEMPOCD, DEMDADR, DEMDTLN, STOTQTY, SALLQTY, SBLOQTY, PLANQTY, PLCMQTY, SUOMKEY, ADDCOKY, POSHPDT, POSHPTM, POSHPDY, SHPLIMT, DELVDSR, STKMEMO, EMSKUYN, RCVDCDT, RCVDCTM, LOTAT01, LOTAT02, LOTAT03, STKSTAT, BLOCKID, RCVDCKY, RCVDCIT, ADJSOKY, ADJSOIT, PHYSOKY, PHYSOIT, SHPDCKY, SHPDCIT, TASKOKY, TASKOIT,
CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK FROM ${userData.schema}.WSTKKY WHERE WAREKEY = #{param.warekey} AND SKUMKEY = #{param.skumkey}
AND STOCKKY = #{param.stockky}
GROUP BY
STOCKKY,
WAREKEY, AREAKEY, LOCAKEY, LOLAYER, SAVEPNT, LOTNMKY, OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM, FNCUSKY, FCNAMLC, SKUGRKY, SKUMKEY, SKUDESC, SKUWEIG, SKUWIDT, SKULENG, SKUTHIC, STLOTNB, GROSSWG, GROSSLN, GROSSWD, GROSSTH, BTRCATE, BTRFSTC, PURCNUM, ORDERLN, REGIKEY, DESTKEY, REGIORG, REGIMOD, DESTORG, DEORGNM, DESTMOD, ITEMCOD, DEMODNM, DEMODYN, DEMDMAN, DEMPOCD, DEMDADR, DEMDTLN, STOTQTY, SALLQTY, SBLOQTY, PLANQTY, PLCMQTY, SUOMKEY, ADDCOKY, POSHPDT, POSHPTM, POSHPDY, SHPLIMT, DELVDSR, STKMEMO, EMSKUYN, RCVDCDT, RCVDCTM, LOTAT01, LOTAT02, LOTAT03, STKSTAT, BLOCKID, RCVDCKY, RCVDCIT, ADJSOKY, ADJSOIT, PHYSOKY, PHYSOIT, SHPDCKY, SHPDCIT, TASKOKY, TASKOIT,
CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK

/* selectOmFilterLocationList */ SELECT ML.WAREKEY , ML.AREAKEY , ML.LOCAKEY , ML.LOCANAM FROM ${userInfo.schema}.MLOCMA ML INNER JOIN ( SELECT LOCAKEY FROM ${userInfo.schema}.MEQLOC WHERE EQUIPKY IN ( SELECT DISTINCT ME.EQUIPKY FROM ${userInfo.schema}.MEQLOC ME INNER JOIN ${userInfo.schema}.WSTKKY WS ON WS.STOCKKY IN
#{item.stockky}
AND WS.LOCAKEY = ME.LOCAKEY WHERE ME.ELUSEYN = 'Y' ) )AS A ON A.LOCAKEY = ML.LOCAKEY WHERE ML.LOCTYPE = 'STP' AND ML.WAREKEY = #{param.warekey} AND ML.LOUSEYN = 'Y'

/* selectTplnitListValidation */
SELECT TI.VHPLNKY
	 , TI.VHPLNIT
	 , WS.STOCKKY
FROM ${userInfo.schema}.TPLNIT TI
LEFT JOIN ${userInfo.schema}.WSTKKY WS
	ON WS.SKUMKEY = TI.SKUMKEY
WHERE TI.WAREKEY = #{param.warekey}
  AND TI.VHPLNKY = #{param.vhplnky}

/* selectTpwpwgListForValidation */
SELECT

	VHPLNKY, SHPPLKY, PLNSIZE,

	ALCWEIG, REGIKEY, WPLCFYN, OOUCFYN,
	SHPCFYN, ARRIVYN,

	CREDATE, CRETIME, CREUSER,
	LMODATE, LMOTIME, LMOUSER,
	UPDTCHK
FROM
	${userInfo.schema}.TPWPWG TWG


		AND VHPLNKY = #{param.vhplnky}


		AND SHPPLKY = #{param.shpplky}


		AND PLNSIZE = #{param.plnsize}

/* selectMaxLayerOfLocation */
SELECT
	MAX(WSK.LOLAYER)
FROM
	${userInfo.schema}.WSTKKY WSK
WHERE
	WSK.WAREKEY = #{param.warekey}
	AND WSK.AREAKEY = #{param.areakey}
	AND WSK.LOCAKEY = #{param.locakey}

mapper.delete:
/* deleteTplnitForChangeInvoice */
DELETE
FROM
	${userInfo.schema}.TPLNIT
WHERE
	WAREKEY = #{param.warekey}
	AND SKUMKEY = #{param.skumkey}
	AND VHPLNKY = #{param.vhplnky}
